#!/usr/bin/env node
/**
 * Phase-2 de-confound — LIGHT bilateral-role-play drama generator.
 *
 * Drives the REAL multi-agent ego/superego architecture (tutor ego→superego→ego,
 * learner ego→superego→ego) over runInteraction — the harness-free path:
 * NO DB, NO scoring, NO rubrics. Each drama in config/poetics-calibration/
 * phase2-dramas-v2.yaml is generated by faithful role-play (NOT one model
 * scripting a "drama"), then neutralized and emitted as a TUTOR:/LEARNER:
 * transcript for the SAME codex instrument + human labeller that ran Phase 2.
 *
 * Why this exists: the Phase-2 gate FAILED (κ=0.044) on a sample with three
 * validity threats (PHASE2-FINDINGS.md §3). This produces a VARIED, de-confounded
 * set so we can re-ask, as a DIAGNOSTIC (n=6, κ is noise — NOT a gate-powered
 * re-run), whether the failure is the instrument's or the sample's.
 *
 * Routing: by default every agent call goes to ONE generator — claude-code CLI
 * (Max-plan quota, not metered API) for --generator claude, or codex exec for
 * --generator codex — regardless of each profile's configured model, so the
 * generator and critic are different models (generator≠critic). The claude bridge
 * is lifted from services/adaptiveTutor/realLLM.js:callClaudeCli: the
 * `--system-prompt` flag REPLACES the default system prompt, which suppresses the
 * explanatory output-style "★ Insight" additions that would otherwise leak into
 * generated turns; the child-env unsets ANTHROPIC_API_KEY so the CLI uses the
 * subscription window instead of billing per call. A --effort <low|medium|high|
 * xhigh|max> is passed through to the claude CLI's reasoning tier and recorded in
 * provenance (e.g. claude-opus-4-8 @xhigh); left unset, the CLI default applies, so
 * the original default-effort claude arm is unchanged. The codex bridge runs at an
 * explicit reasoning tier (CODEX_REASONING_EFFORT, default xhigh) so the setting
 * is recorded by the run, not silently inherited from ~/.codex/config.toml.
 *
 * Mixed authorship: --role-map routes individual dialogue roles to different
 * models in the SAME drama (e.g. a Claude tutor with a codex learner, or a
 * cross-model superego). This deliberately breaks the single-author/critic
 * symmetry — a mixed drama has no clean arms-length automated critic, so lean on
 * the human labeller. Roles: director, tutor_ego, tutor_superego, learner_ego,
 * learner_superego. The ego role is stable; "initial" vs "adjudication" is a
 * stage on the same role, not a separate actor.
 *
 * Blinding (mirrors load-poetics-phase2-sample.js): only EXTERNAL turns and
 * visible STAGE directions are emitted to the sample. Internal ego/superego
 * deliberation is written to a SEPARATE held-out dir and never reaches the critic
 * or labeller — the unit of analysis is the transcript-as-drama, not an agent's
 * interior (the arc's "no concealed-interior signal" rule). The held-out key
 * (discipline / condition / intended-lean / dramatic-shape) joins to scores +
 * labels only AFTER both.
 *
 * Cost posture: these dramas share a quota window AND feed between-condition
 * contrasts. They run sequentially by default; pass --generation-concurrency N
 * for attended parallel runs when quota/rate limits allow it. Each drama is
 * written as soon as it completes and existing outputs are skipped, so a
 * quota-interrupted run resumes by re-running.
 *
 * Usage:
 *   node scripts/generate-pedagogical-dramas.js --dry-run        # plan only, no LLM, no writes
 *   node scripts/generate-pedagogical-dramas.js --mock           # full pipeline, stub LLM, *-mock dirs (free)
 *   node scripts/generate-pedagogical-dramas.js                  # REAL claude-code CLI (attended, paid quota)
 *   node scripts/generate-pedagogical-dramas.js --only D6        # one drama (debug)
 *   node scripts/generate-pedagogical-dramas.js --force          # overwrite existing sample dir
 *
 * Flags: --seed N (T-id shuffle, default 20260520) · --max-turns N (default 6)
 *        --model <alias> (claude CLI --model, default opus; e.g. claude-opus-4-8)
 *        --effort low|medium|high|xhigh|max (claude CLI reasoning tier; claude
 *          backend only — codex uses CODEX_REASONING_EFFORT, agy has no effort knob)
 *        --out-dir / --key · --delib-dir / --transcripts-dir / --writing-pad-dir
 *        --generator claude|codex|gemini · --role-map "tutor=codex,learner=claude" (mixed)
 *        --director-revisit-cue (anchor shorthand) · --director-revisit-policy none|anchor|revoice|reconsider|reframe
 *        --director-revisit-anchor latest|opening|misframing-candidate
 *        --director-variation-key <repeat-or-batch-id>
 *        --paired-continuation-policies none,revoice,reconsider,reframe
 *        --paired-adaptation-arms routine,none,reframe-only,tutor-uptake-only,reframe+tutor-uptake,peripeteia-only,reframe+peripeteia
 *        --generation-concurrency N (default 1; independent dramas only)
 * Env:   CODEX_REASONING_EFFORT (default xhigh) · CODEX_MODEL (default: codex config)
 */

import 'dotenv/config';
import fs from 'node:fs';
import os from 'node:os';
import path from 'node:path';
import { spawn } from 'node:child_process';
import { fileURLToPath } from 'node:url';
import { createHash } from 'node:crypto';
import yaml from 'yaml';
import { jsonrepair } from 'jsonrepair';
import { createProgressReporter, runTasksWithConcurrency } from './progress.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKTREE_ROOT = path.resolve(__dirname, '..');
const CAL_DIR = path.join(WORKTREE_ROOT, 'config', 'poetics-calibration');
const DRAMAS_SPEC = path.join(CAL_DIR, 'phase2-dramas-v2.yaml');
const PEDAGOGICAL_APPROACHES_DB = path.join(CAL_DIR, 'pedagogical-approaches.yaml');
const DIALOGUE_APPROACHES_DB = path.join(CAL_DIR, 'dialogue-approaches.yaml');
const DIRECTOR_REVISIT_POLICIES = new Set(['none', 'anchor', 'revoice', 'reconsider', 'reframe']);
const DIRECTOR_REVISIT_ANCHORS = new Set(['latest', 'opening', 'misframing-candidate']);
const TUTOR_ADAPTATION_POLICIES = new Set(['none', 'routine', 'uptake', 'peripeteia', 'uptake+peripeteia']);
// claude CLI reasoning tiers (`claude --effort <level>`). codex tops out at xhigh;
// the claude CLI adds a `max` tier above it. Used by the claude backend only —
// agy exposes no effort flag, and codex reads CODEX_REASONING_EFFORT (env).
const CLAUDE_EFFORT_LEVELS = new Set(['low', 'medium', 'high', 'xhigh', 'max']);
const PAIRED_ADAPTATION_ARMS = {
  routine: { revisitPolicy: 'none', tutorAdaptationPolicy: 'routine' },
  none: { revisitPolicy: 'none', tutorAdaptationPolicy: 'none' },
  'reframe-only': { revisitPolicy: 'reframe', tutorAdaptationPolicy: 'none' },
  'tutor-uptake-only': { revisitPolicy: 'none', tutorAdaptationPolicy: 'uptake' },
  'reframe+tutor-uptake': { revisitPolicy: 'reframe', tutorAdaptationPolicy: 'uptake' },
  'peripeteia-only': { revisitPolicy: 'none', tutorAdaptationPolicy: 'peripeteia' },
  'reframe+peripeteia': { revisitPolicy: 'reframe', tutorAdaptationPolicy: 'uptake+peripeteia' },
};

// ── args ─────────────────────────────────────────────────────────────────────

function parseArgs(argv) {
  const a = {
    seed: 20260520,
    maxTurns: 6,
    model: 'opus',
    effort: null,
    generator: 'claude',
    spec: null,
    pedagogyDb: PEDAGOGICAL_APPROACHES_DB,
    dialogueDb: DIALOGUE_APPROACHES_DB,
    tidStart: 0,
    mock: false,
    dryRun: false,
    force: false,
    reclean: false,
    only: null,
    outDir: null,
    delibDir: null,
    transcriptsDir: null,
    keyPath: null,
    writingPadDir: null,
    roleMap: null,
    directorMode: 'scene',
    directorRevisitPolicy: 'none',
    directorRevisitAnchor: 'latest',
    directorVariationKey: null,
    pairedContinuationPolicies: null,
    pairedAdaptationArms: null,
    generationConcurrency: 1,
  };
  for (let i = 0; i < argv.length; i++) {
    const t = argv[i];
    if (t === '--mock') a.mock = true;
    else if (t === '--dry-run') a.dryRun = true;
    else if (t === '--force') a.force = true;
    else if (t === '--reclean') a.reclean = true;
    else if (t === '--seed') a.seed = parseInt(argv[++i], 10);
    else if (t === '--max-turns') a.maxTurns = parseInt(argv[++i], 10);
    else if (t === '--model') a.model = argv[++i];
    else if (t === '--effort') a.effort = argv[++i];
    else if (t === '--generator') a.generator = argv[++i];
    else if (t === '--spec') a.spec = path.resolve(argv[++i]);
    else if (t === '--pedagogy-db') a.pedagogyDb = path.resolve(argv[++i]);
    else if (t === '--dialogue-db') a.dialogueDb = path.resolve(argv[++i]);
    else if (t === '--tid-start') a.tidStart = parseInt(argv[++i], 10);
    else if (t === '--only') a.only = argv[++i];
    else if (t === '--out-dir') a.outDir = path.resolve(argv[++i]);
    else if (t === '--delib-dir') a.delibDir = path.resolve(argv[++i]);
    else if (t === '--transcripts-dir') a.transcriptsDir = path.resolve(argv[++i]);
    else if (t === '--key') a.keyPath = path.resolve(argv[++i]);
    else if (t === '--writing-pad-dir') a.writingPadDir = path.resolve(argv[++i]);
    else if (t === '--role-map') a.roleMap = parseRoleMap(argv[++i]);
    else if (t === '--director-mode') a.directorMode = argv[++i];
    else if (t === '--director-revisit-cue') a.directorRevisitPolicy = 'anchor';
    else if (t === '--director-revisit-policy') a.directorRevisitPolicy = argv[++i];
    else if (t === '--director-revisit-anchor') a.directorRevisitAnchor = argv[++i];
    else if (t === '--director-variation-key') a.directorVariationKey = argv[++i];
    else if (t === '--paired-continuation-policies') {
      a.pairedContinuationPolicies = String(argv[++i] || '')
        .split(',')
        .map((policy) => policy.trim())
        .filter(Boolean);
    } else if (t === '--paired-adaptation-arms') {
      a.pairedAdaptationArms = String(argv[++i] || '')
        .split(',')
        .map((arm) => arm.trim())
        .filter(Boolean);
    } else if (t === '--generation-concurrency') a.generationConcurrency = parseInt(argv[++i], 10);
    else throw new Error(`unknown arg: ${t}`);
  }
  if (!Number.isInteger(a.seed)) throw new Error('--seed must be an integer');
  if (!Number.isInteger(a.maxTurns) || a.maxTurns < 1) throw new Error('--max-turns must be a positive integer');
  if (a.generator !== 'claude' && a.generator !== 'codex' && a.generator !== 'gemini')
    throw new Error(`--generator must be claude|codex|gemini (got ${a.generator})`);
  if (a.effort && !CLAUDE_EFFORT_LEVELS.has(a.effort))
    throw new Error(`--effort must be low|medium|high|xhigh|max (got ${a.effort})`);
  if (!Number.isInteger(a.tidStart) || a.tidStart < 0) throw new Error('--tid-start must be a non-negative integer');
  if (!Number.isInteger(a.generationConcurrency) || a.generationConcurrency < 1) {
    throw new Error('--generation-concurrency must be a positive integer');
  }
  if (a.pedagogyDb && !fs.existsSync(a.pedagogyDb)) throw new Error(`--pedagogy-db not found: ${a.pedagogyDb}`);
  if (a.dialogueDb && !fs.existsSync(a.dialogueDb)) throw new Error(`--dialogue-db not found: ${a.dialogueDb}`);
  if (!['off', 'scene'].includes(a.directorMode)) throw new Error('--director-mode must be off|scene');
  if (!DIRECTOR_REVISIT_POLICIES.has(a.directorRevisitPolicy))
    throw new Error('--director-revisit-policy must be none|anchor|revoice|reconsider|reframe');
  if (!DIRECTOR_REVISIT_ANCHORS.has(a.directorRevisitAnchor))
    throw new Error('--director-revisit-anchor must be latest|opening|misframing-candidate');
  if (a.pairedContinuationPolicies) {
    if (!a.pairedContinuationPolicies.length)
      throw new Error('--paired-continuation-policies needs at least one policy');
    for (const policy of a.pairedContinuationPolicies) {
      if (!DIRECTOR_REVISIT_POLICIES.has(policy)) {
        throw new Error('--paired-continuation-policies must use none|anchor|revoice|reconsider|reframe');
      }
    }
  }
  if (a.pairedAdaptationArms) {
    if (!a.pairedAdaptationArms.length) throw new Error('--paired-adaptation-arms needs at least one arm');
    for (const arm of a.pairedAdaptationArms) {
      if (!PAIRED_ADAPTATION_ARMS[arm]) {
        throw new Error(
          '--paired-adaptation-arms must use routine,none,reframe-only,tutor-uptake-only,reframe+tutor-uptake,peripeteia-only,reframe+peripeteia',
        );
      }
    }
  }
  if (a.pairedContinuationPolicies && a.pairedAdaptationArms) {
    throw new Error('use either --paired-continuation-policies or --paired-adaptation-arms, not both');
  }
  a.spec = a.spec || DRAMAS_SPEC;
  // Default output locations are GENERATOR-AWARE so the arms never collide:
  //   claude (default effort) → phase2-sample-v2 (the running Arm-A set);
  //   claude --effort <lvl>   → phase2-sample-claude-<lvl> (its own arm, e.g. the
  //     `claude-opus-4-8 @xhigh` set, so a pinned-reasoning run never overwrites Arm-A);
  //   codex → phase2-sample-codex; gemini → phase2-sample-gemini;
  //   a --role-map → phase2-sample-mixed (distinct maps share it — pass --out-dir to
  //   separate them). mock adds a -mock suffix so a wiring smoke never clobbers a
  //   real labelling set. Real comparison runs usually pass explicit --out-dir anyway.
  const base = a.roleMap
    ? 'mixed'
    : a.generator === 'codex'
      ? 'codex'
      : a.generator === 'gemini'
        ? 'gemini'
        : a.effort
          ? `claude-${a.effort}`
          : 'v2';
  const suffix = a.mock ? '-mock' : '';
  a.outDir = a.outDir || path.join(CAL_DIR, `phase2-sample-${base}${suffix}`);
  a.delibDir = a.delibDir || path.join(CAL_DIR, `phase2-deliberation-${base}${suffix}`);
  a.transcriptsDir = a.transcriptsDir || path.join(CAL_DIR, `phase2-transcripts-${base}${suffix}`);
  a.keyPath = a.keyPath || path.join(CAL_DIR, `phase2-key-${base}${suffix}.yaml`);
  a.writingPadDir = a.writingPadDir || path.join(a.delibDir, '.writing-pad');
  // --effort drives the claude backend only. Warn (don't throw) if it can't reach
  // claude: a pure codex/gemini run, or a --role-map that routes no role to claude.
  const claudeReachable = a.generator === 'claude' || (a.roleMap && Object.values(a.roleMap).includes('claude'));
  if (a.effort && !claudeReachable) {
    console.warn(
      `[warn] --effort ${a.effort} only affects the claude backend; generator=${a.generator} ignores it ` +
        `(codex reads CODEX_REASONING_EFFORT, agy exposes no effort flag)`,
    );
  }
  return a;
}

function resolveDirectorRevisitOptions(d, args) {
  const policy = d.director_revisit_policy ?? args.directorRevisitPolicy;
  const anchor = d.director_revisit_anchor ?? args.directorRevisitAnchor;
  if (!DIRECTOR_REVISIT_POLICIES.has(policy)) {
    throw new Error(
      `drama ${d.id || '<unknown>'} director_revisit_policy must be none|anchor|revoice|reconsider|reframe`,
    );
  }
  if (!DIRECTOR_REVISIT_ANCHORS.has(anchor)) {
    throw new Error(`drama ${d.id || '<unknown>'} director_revisit_anchor must be latest|opening|misframing-candidate`);
  }
  return { policy, anchor: policy === 'none' ? null : anchor };
}

function summarizeDirectorRevisitOptions(dramas) {
  const policies = [...new Set(dramas.map((d) => d._directorRevisitPolicy || 'none'))];
  const anchors = [
    ...new Set(
      dramas
        .filter((d) => d._directorRevisitPolicy && d._directorRevisitPolicy !== 'none')
        .map((d) => d._directorRevisitAnchor || 'latest'),
    ),
  ];
  return {
    cue: policies.some((policy) => policy !== 'none'),
    policy: policies.length === 1 ? policies[0] : 'mixed',
    anchor: anchors.length === 0 ? null : anchors.length === 1 ? anchors[0] : 'mixed',
  };
}

// ── seeded PRNG (mulberry32) + Fisher–Yates  (lifted from load-poetics) ───────

function mulberry32(seed) {
  let s = seed >>> 0;
  return function () {
    s = (s + 0x6d2b79f5) | 0;
    let t = Math.imul(s ^ (s >>> 15), 1 | s);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

function shuffled(arr, rng) {
  const a = arr.slice();
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(rng() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// ── neutralization (identical to load-poetics-phase2-sample.js) ──────────────

const IDENTITY_PATTERNS = [
  [/\b(anthropic|openai|google\s+deepmind|deepmind|openrouter)\b/gi, '[provider]'],
  [/\b(claude|chatgpt|gpt-?\d(?:\.\d)?|gemini(?:\s*flash)?|gemflash|nemotron|llama|mistral)\b/gi, '[model]'],
  [/\b(haiku|sonnet|opus)\b/gi, '[model]'],
  [/\bas an? (?:ai|large )?language model\b/gi, 'as a tutor'],
];

function neutralize(text) {
  let out = text;
  for (const [re, rep] of IDENTITY_PATTERNS) out = out.replace(re, rep);
  return out
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

// Recognition-condition tutors sometimes emit a DIRECTOR'S NOTE inside their
// spoken turn — a meta-instruction to their future self that NAMES the intended
// dramatic shape ("Next turn, deploy the population reframe … they may reach for
// it before you offer it"). Left in the transcript it primes the labeller toward
// "recognition": the answer key bleeding into the blind. We strip two signatures:
//   (1) italic-wrapped parentheticals  *( … )*  — the stage-direction typography;
//       in-drama asides to the learner are plain, second-person, inside the quote.
//   (2) a PLAIN parenthetical whose content is director-voiced — third-person
//       "the learner", or planning verbs ("next turn"/"deploy"/"the draft").
// Legit second-person asides ("(say the why first; it's yours to finish)") never
// match cue (2) and are kept. The held-out JSON retains the unstripped text; every
// strip is logged to a sidecar so the heuristic can be audited by eye at small n.
const DIRECTOR_CUES =
  /\b(next turn|the learner\b|deploy\b|the draft|once the learner|they (?:may|might|will|already)|almost as written|the (?:population )?reframe\b|the move\b|this turn,? (?:once|after))\b/i;

function stripStageDirections(text) {
  const removed = [];
  let out = text;
  // (0) ★ Insight blocks: output-style scaffolding that leaks from a spawned
  // claude CLI child (the "explanatory" style rides along even when --system-prompt
  // replaces the system prompt). It speaks in the evaluation architecture's voice
  // ("the revision protects…", "the draft handed the learner…") and must never
  // reach a transcript. Matches the backtick-wrapped "★ Insight ───" opener through
  // the "───" closer.
  out = out.replace(/`?★\s*Insight\s*─+`?[\s\S]*?`?─{5,}`?/g, (m) => {
    removed.push(m);
    return '';
  });
  // (1) italic-wrapped parentheticals: *( ... )*  (may span lines)
  out = out.replace(/\*\(([\s\S]*?)\)\*/g, (m) => {
    removed.push(m);
    return '';
  });
  // (2) plain parenthetical with director voice (3rd-person / planning verbs)
  out = out.replace(/\(([^)]*)\)/g, (m, inner) => {
    if (DIRECTOR_CUES.test(inner)) {
      removed.push(m);
      return '';
    }
    return m;
  });
  out = out
    .replace(/[ \t]{2,}/g, ' ')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
  return { text: out, removed };
}

function bracketAsideText(text) {
  const chunks = String(text || '')
    .trim()
    .split(/\n+/)
    .map((chunk) => chunk.replace(/[[\]]/g, '').trim())
    .filter(Boolean);
  return chunks.map((chunk) => `[${chunk}]`).join('\n');
}

const ACTION_ASIDE_CUE =
  /\b(?:adjusts?|checks?|circles?|draws?|gestures?|holds?|leans?|looks?|marks?|nods?|pauses?|points?|reads?|sets?|shows?|slides?|smiles?|taps?|turns?|underlines?|writes?)\b/i;

function normalizeSpeakerActionAsides(text) {
  return String(text || '')
    .replace(/(^|[\s])\(([^)\n]{2,120})\)/g, (match, prefix, inner) => {
      const actionLike = ACTION_ASIDE_CUE.test(inner) && !/[=<>]/.test(inner);
      return actionLike ? `${prefix}${bracketAsideText(inner)}` : match;
    })
    .trim();
}

function stripWrappingSpeechQuotes(text) {
  const trimmed = String(text || '').trim();
  const pairs = [
    ['"', '"'],
    ["'", "'"],
    ['\u201c', '\u201d'],
    ['\u2018', '\u2019'],
  ];
  const pair = pairs.find(([open, close]) => trimmed.startsWith(open) && trimmed.endsWith(close));
  if (!pair || trimmed.length < 2) return trimmed;
  return trimmed.slice(pair[0].length, trimmed.length - pair[1].length).trim();
}

function splitLeadingActionAsides(text) {
  const trimmed = String(text || '').trim();
  const match = trimmed.match(/^((?:\[[^\]\n]+\]\s*)+)([\s\S]*)$/);
  if (!match) return { asides: '', speech: trimmed };
  return {
    asides: match[1].trim(),
    speech: match[2].trim(),
  };
}

function quotePublicSpeech(text) {
  const speech = String(text || '').trim();
  if (!speech) return '';
  return `"${speech}"`;
}

function formatPublicTurnText(role, text) {
  const clean = String(text || '').trim();
  if (!clean) return '';
  if (role === 'STAGE') return bracketAsideText(clean);
  const normalized = normalizeSpeakerActionAsides(clean);
  const { asides, speech } = splitLeadingActionAsides(normalized);
  if (!speech) return asides;
  const directSpeech = quotePublicSpeech(stripWrappingSpeechQuotes(speech));
  return asides ? `${asides}\n\n${directSpeech}` : directSpeech;
}

function renderTranscript(turns, removedSink) {
  return (
    turns
      .map((t) => {
        const { text, removed } = stripStageDirections(neutralize(t.text));
        if (removedSink && removed.length) removed.forEach((r) => removedSink.push({ role: t.role, note: r }));
        return `${t.role}: ${formatPublicTurnText(t.role, text)}`;
      })
      .join('\n\n') + '\n'
  );
}

function publicReaderContextText(plan) {
  const explicit = String(plan?.public_reader_context || '').trim();
  if (explicit) return explicit;
  return '';
}

function publicStageDirectionText(text) {
  return String(text || '')
    .trim()
    .replace(
      /;\s*(?:the tutor|the learner|the next speaker|the next reply)\s+(?:must|has to|should)\b[^.?!]*(?:[.?!]|$)/gi,
      '.',
    )
    .replace(
      /\b(?:the tutor|the learner|the next speaker|the next reply)\s+(?:must|has to|should)\b[^.?!]*(?:[.?!]|$)/gi,
      '',
    )
    .replace(/^The director places the tutor\b/i, 'The tutor stands')
    .replace(/^The director places the learner\b/i, 'The learner stands')
    .replace(/^The director (?:sets|opens) (?:the )?scene:?\s*/i, '')
    .replace(/^The director\s+/i, '')
    .replace(/\bscene card\b/gi, 'scene')
    .replace(/\bthe next (tutor|learner) line must be\b/gi, 'the next $1 line is')
    .replace(/\bthe next speaker must\b/gi, 'the next reply has to')
    .replace(/\bthe learner must\b/gi, 'the learner has to')
    .replace(/\bthe tutor must\b/gi, 'the tutor has to')
    .replace(
      /\bEnd the scene with one concise tutor line\. Do not ask the learner to continue unless the scene genuinely needs it\./gi,
      'A final tutor line closes the scene.',
    )
    .trim();
}

// A learner turn is "truncated" (generation-time max_tokens clip) if it does not
// end in sentence-final punctuation — a clipped fragment cannot be judged for
// recohering. We don't auto-exclude at n=6; we WARN so the drama can be regenerated.
function isTruncated(text) {
  return !/[.?!…"”'’)\]]$/.test(text.trim());
}

function previousStageAllowsFragment(turns, index) {
  for (let i = index - 1; i >= 0; i--) {
    if (turns[i]?.role !== 'STAGE') continue;
    return /\bunfinished\b/i.test(turns[i].text);
  }
  return false;
}

const REVOICE_STOPWORDS = new Set([
  'about',
  'after',
  'again',
  'also',
  'and',
  'are',
  'before',
  'but',
  'can',
  'could',
  'does',
  'for',
  'from',
  'had',
  'has',
  'have',
  'here',
  'how',
  'into',
  'its',
  'just',
  'like',
  'must',
  'not',
  'now',
  'one',
  'out',
  'that',
  'the',
  'then',
  'there',
  'this',
  'too',
  'was',
  'what',
  'when',
  'where',
  'which',
  'while',
  'with',
  'would',
  'you',
  'your',
]);

function revoiceTerms(text) {
  return [
    ...new Set(
      String(text || '')
        .toLowerCase()
        .match(/[a-z0-9]+(?:['’][a-z0-9]+)?/g)
        ?.filter((term) => (term.length > 2 || /\d/.test(term)) && !REVOICE_STOPWORDS.has(term)) || [],
    ),
  ];
}

function extractRevisitAnchor(text) {
  return (
    String(text || '').match(
      /(?:A prior learner line is played back|An earlier learner line returns to the table):\s*"([\s\S]*?)"\s*(?:The learner must|The pause holds|The next response|The learner has to)/i,
    )?.[1] || ''
  );
}

function isAnchoredRevisitCueText(text) {
  return /(?:A prior learner line is played back|An earlier learner line returns to the table):/i.test(
    String(text || ''),
  );
}

function isReframeCueText(text) {
  const cueText = String(text || '');
  return (
    /The learner must revoice that wording first,\s*name the earlier framing problem/i.test(cueText) ||
    (isAnchoredRevisitCueText(cueText) &&
      (/\bold frame\b[\s\S]{0,120}\breplacement frame\b/i.test(cueText) || /three-slot reframe card/i.test(cueText)))
  );
}

function isRevoiceOrReconsiderCueText(text) {
  const cueText = String(text || '');
  if (!isAnchoredRevisitCueText(cueText)) return false;
  if (isReframeCueText(cueText)) return false;
  return (
    /The learner must revoice that wording/i.test(cueText) ||
    /The learner must answer that wording/i.test(cueText) ||
    /what (?:it|that wording) now misses, keeps, or changes/i.test(cueText) ||
    /still stands, needs narrowing, or needs replacing/i.test(cueText)
  );
}

function revoiceMatchStats(anchor, learnerText) {
  const anchorTerms = revoiceTerms(anchor);
  const normalizedLearner = String(learnerText || '')
    .replace(/\s+/g, ' ')
    .trim();
  const learnerOpeningProbe = normalizedLearner.replace(/\.{2,}/g, '…');
  const firstSentence = learnerOpeningProbe.match(/^.*?[.!?](?=\s|$)/)?.[0] || '';
  const minimumSharedTerms = Math.min(3, anchorTerms.length);
  const learnerOpening =
    firstSentence && revoiceTerms(firstSentence).length >= minimumSharedTerms
      ? firstSentence
      : normalizedLearner.slice(0, 220);
  const learnerTerms = new Set(revoiceTerms(learnerOpening));
  const sharedTerms = anchorTerms.filter((term) => learnerTerms.has(term));
  const overlapRatio = anchorTerms.length ? sharedTerms.length / anchorTerms.length : 0;
  return {
    anchor_terms: anchorTerms.length,
    learner_opening_terms: learnerTerms.size,
    shared_terms: sharedTerms.length,
    overlap_ratio: Number(overlapRatio.toFixed(3)),
    compliant: minimumSharedTerms > 0 && sharedTerms.length >= minimumSharedTerms && overlapRatio >= 0.2,
  };
}

function revoiceComplianceFailures(turns) {
  const failures = [];
  for (let i = 0; i < turns.length; i++) {
    const cue = turns[i];
    if (cue.role !== 'STAGE' || !isRevoiceOrReconsiderCueText(cue.text)) {
      continue;
    }
    const anchor = extractRevisitAnchor(cue.text);
    const learner = turns.slice(i + 1).find((turn) => turn.role !== 'STAGE');
    const stats = revoiceMatchStats(anchor, learner?.role === 'LEARNER' ? learner.text : '');
    if (anchor && learner?.role === 'LEARNER' && stats.compliant) continue;
    failures.push({
      stage_turn_number: cue.turnNumber ?? i + 1,
      learner_turn_number: learner?.turnNumber ?? null,
      reason: !anchor
        ? 'missing_anchor'
        : learner?.role !== 'LEARNER'
          ? 'missing_followup_learner'
          : 'low_anchor_overlap',
      ...stats,
    });
  }
  return failures;
}

function namesEarlierFramingProblem(text) {
  const learnerText = String(text || '');
  const explicitProblem =
    /\b(?:fram(?:e|ed|ing)|reading|read|assumption|assumed|treat(?:ed|ing))\b[\s\S]{0,80}\b(?:problem|trouble|issue|mistake|trap|miss(?:es|ed)?|wrong|off|bad(?:ly)?|too\s+\w+|premature|skips?|flattens?|erases?)\b/i;
  const explicitReverse =
    /\b(?:problem|trouble|issue|mistake|trap|miss(?:es|ed)?|wrong|off|bad(?:ly)?|too\s+\w+|premature|skips?|flattens?|erases?)\b[\s\S]{0,80}\b(?:fram(?:e|ed|ing)|reading|read|assumption|assumed|treat(?:ed|ing)|tak(?:e|ing))\b/i;
  const selfCorrection =
    /\b(?:I|that)\s+(?:jumped|rushed|mistook|reduced|flattened|skipped)\b[\s\S]{0,80}\b(?:before|into|to|the)\b/i;
  const earlierFramingCorrection =
    /\b(?:earlier|old|first)\s+(?:framing|frame|reading)\b[\s\S]{0,100}\b(?:made it sound|sounded|treated|put|reduced|jumped|mistook|too)\b/i;
  const ordinarySelfCorrection = [
    /\bthat\s+was\s+the\s+problem\b/i,
    /\bbad\s+wording\b[\s\S]{0,90}\b(?:counted|treated|missed|hid|made|put)\b/i,
    /\b(?:the\s+)?mistake\s+(?:was|is)\s+that\b/i,
    /\b(?:that|it)\s+(?:was|put|made)\b[\s\S]{0,90}\b(?:too\s+\w+|mood first|sound like|ahead|early)\b/i,
    /\bI\s+(?:was still|was putting|was making|kept|went straight|made|put)\b[\s\S]{0,90}\b(?:sound like|too\s+\w+|mood first|before|ahead|again|into|mean)\b/i,
    /\bI\s+(?:said|treated|read)\b[\s\S]{0,90}\bas\s+if\b/i,
    /\b(?:that|this|it|my old framing|the old read|that old wording|old wording|that way of saying it)\b[\s\S]{0,90}\b(?:hid|hides|hiding|made it sound|makes it sound)\b/i,
    /\b(?:that|this|it|my old framing|the old read|that old wording|old wording|that way of saying it)\b[\s\S]{0,90}\b(?:only going by|only counting|not asking)\b/i,
    /\b(?:problem|trouble|issue)\s+with\s+(?:that|this|it)\s+is\b/i,
    /\bI\s+was\s+still\s+acting\s+like\b/i,
    /\bI\s+was\s+letting\b[\s\S]{0,90}\btoo much\b/i,
    /\b(?:too[-\s]easy|too[-\s]simple)\s+(?:bit|part|move|shortcut)\b[\s\S]{0,90}\b(?:treat(?:ed|ing)?|made|hid|skipped|bundled)\b/i,
    /\bproblem\s+is\s+that\s+I\s+was\s+letting\b/i,
    /\bthat\s+was\s+me\s+letting\b[\s\S]{0,90}\bmean\b/i,
    /\bI\s+was\s+using\b[\s\S]{0,90}\bas\s+the\s+clue\b/i,
    /\bI\s+let\b[\s\S]{0,90}\bdecide\b[\s\S]{0,90}\bbefore checking\b/i,
    /\bI\s+let\b[\s\S]{0,90}\bbe\s+the\s+whole\b[\s\S]{0,90}\bbefore\b/i,
    /\bproblem\s+is\s+I\s+(?:put|placed|located|made|treated)\b/i,
    /\bproblem\s+was\s+making\b/i,
    /\b(?:I|it|that|this)?\s*was\s+still\s+making\b[\s\S]{0,90}\bsound\s+like\b/i,
    /\bmesses\s+with\s+my\s+frame\b[\s\S]{0,120}\b(?:treating|treated)\b/i,
    /\b(?:I|we)\s+was\s+treating\b[\s\S]{0,90}\blike\s+a\s+(?:confession|verdict|judge|proof|alibi)\b/i,
    /\bmixing\s+up\b[\s\S]{0,90}\bwith\b/i,
    /\b(?:was|is)\s+(?:only|just)\b[\s\S]{0,90}\b(?:not|rather than)\b/i,
    /\btreat(?:ed|ing)\b[\s\S]{0,90}\bas\s+(?:absent|gone|empty|not\s+there)\b/i,
    /\btreat(?:ed|ing)\b[\s\S]{0,90}\bas if\b/i,
    /\bfram(?:e|ed|ing|es)\b[\s\S]{0,90}\bas\b[\s\S]{0,80}\b(?:only|just)\b/i,
    /\b(?:I|that|it)\s+(?:was\s+)?(?:making|asking)\b[\s\S]{0,90}\btoo much\b/i,
    /\b(?:fram(?:e|ed|ing)|reading)\b[\s\S]{0,90}\basks?\b[\s\S]{0,90}\b(?:do|carry)\b[\s\S]{0,60}\bwork\b/i,
    /\bproblem\b[\s\S]{0,90}\bcalled\b[\s\S]{0,90}\bbefore\b/i,
    /\b(?:made|makes)\b[\s\S]{0,90}\bstand in for\b/i,
    /\b(?:made|makes|making)\b[\s\S]{0,90}\bcount as\b/i,
    /\b(?:reading|read)\b[\s\S]{0,90}\bmix(?:es|ed)? up\b/i,
    /\b(?:that|it)\s+puts?\b[\s\S]{0,90}\bfirst\b/i,
    /\bfram(?:e|ed|ing)\b[\s\S]{0,90}\blike\b/i,
    /\b(?:earlier|old|first)\s+(?:framing|frame|reading)\b[\s\S]{0,100}\b(?:stops?|ends?)\b/i,
    /\b(?:that|it)\s+was\s+me\s+(?:going|judging)\s+by\b/i,
    /\bmy earlier wording\b[\s\S]{0,100}\b(?:shortcut|too simple|too easy|hid|made)\b/i,
    /\b(?:same|matching|position|slot|word|number|label|bracket|box|field)\b[\s\S]{0,80}\btrap\b/i,
    /\btrap\b[\s\S]{0,80}\b(?:same|matching|position|slot|word|number|label|bracket|box|field)\b/i,
    /\b(?:pull|pulls|pulled|pulling)\s+(?:me|my eye|my attention)\b[\s\S]{0,100}\b(?:but|so|because|still|now)\b/i,
  ].some((pattern) => pattern.test(learnerText));
  return (
    explicitProblem.test(learnerText) ||
    explicitReverse.test(learnerText) ||
    selfCorrection.test(learnerText) ||
    earlierFramingCorrection.test(learnerText) ||
    ordinarySelfCorrection
  );
}

function noCuePrematureClosureFailures(turns) {
  const insightPatterns = [
    /\b(?:oh[, ]*)?I\s+(?:get|got|see|understand)\s+it\b/i,
    /\b(?:now|okay|right)[, ]+\s*I\s+(?:get|see|understand)\b/i,
    /\bthat\s+(?:makes sense|clears it up|clicks|helps)\b/i,
    /\b(?:aha|ohh|ohhh)\b/i,
    /\bthe\s+rule\s+(?:is|basically|seems to be)\b/i,
    /\bso\s+(?:the|this|that)\s+(?:rule|test|point|lesson)\s+(?:is|means)\b/i,
  ];
  return (turns || [])
    .filter((turn) => turn.role === 'LEARNER')
    .flatMap((turn) => {
      const text = String(turn.text || '');
      const matched = insightPatterns.find((pattern) => pattern.test(text));
      return matched
        ? [
            {
              turn_number: turn.turnNumber ?? null,
              matched_pattern: matched.source,
              excerpt: text.slice(0, 240),
            },
          ]
        : [];
    });
}

function replacesEarlierFraming(text) {
  const learnerText = String(text || '');
  return [
    /\b(?:instead|rather|now)\b[\s\S]{0,100}\b(?:frame|read|say|put|treat|write|claim)\b/i,
    /\b(?:frame|read|say|put|treat|write|claim)\b[\s\S]{0,80}\b(?:instead|rather|now)\b/i,
    /\b(?:new|better|revised|replacement)\s+(?:frame|framing|reading|standard|criterion|test|question|claim|rule)\b/i,
    /\b(?:standard|rule|criterion|test|question)\s+(?:is|=)\b/i,
    /\b(?:new|better|revised)\s+(?:check|test|claim|question)\s+(?:is|starts?|uses?|asks?)\b/i,
    /\bnew\s+(?:margin\s+note|mark|label|line|frame)\s*:/i,
    /\bbetter\s+(?:note|mark|label|line|frame)\s*:/i,
    /\bnew\s+(?:read|reading)\s*:/i,
    /\breplacement\s+is\b/i,
    /\breplace\s+it\s*:/i,
    /\breplace\s+it\s+with\b/i,
    /\breplace\b[\s\S]{0,80}\bwith\s*:/i,
    /\breframe\b[\s\S]{0,80}\bas\s*:/i,
    /\bI[’']d\s+change\s+it\s+to\b/i,
    /\bI[’']d\s+replace\s+it\s+with\b/i,
    /\breframe\s*:/i,
    /\bbetter\s+(?:reading|line|claim|sentence|note|wording)\s+(?:is|seems? to be)\b/i,
    /\bbetter\s+way\s+(?:is|to\s+(?:put|say)\s+it\s+is)\b/i,
    /\bI\s+(?:would|should|need to|can|will)\s+(?:frame|read|say|put|treat|write|claim|change|call)\b/i,
    /\bmaybe\s+I\s+(?:should|would|need to|can)\s+(?:frame|read|say|put|treat|write|claim|change|call)\b/i,
    /\bso\s+the\b[\s\S]{0,90}\b(?:would|should|is|becomes?)\b/i,
    /\b(?:fresh\s+)?scar\b[\s\S]{0,90}\bwould\s+be\b[\s\S]{0,120}\b(?:event|route|system)\b/i,
    /\b(?:the|this)\s+(?:form|line|label|claim|sentence|answer)\s+should\s+(?:say|read|show)\b/i,
    /\b(?:introduction|question|sentence|clipboard|chart|table)\s+should\s+(?:say|ask|read|show|make|prompt|stay|remain)\b/i,
    /\b(?:line|claim|proof|equation|step)\b[\s\S]{0,40}\b(?:is|starts?|reads?|works?|shows?|means?|puts?|becomes?|tests?)\b/i,
    /\b(?:image|word)\s+(?:now\s+)?(?:starts?|reads?|works?|shows?|means?|puts?|becomes?)\b/i,
    /\b(?:it|that|this)\s+(?:now\s+)?(?:means?|reads?|becomes?)\b/i,
    /\b(?:not just|not only)\b[\s\S]{0,120}\bbut\b/i,
    /\bhere\b[\s\S]{0,120}\b(?:makes?|gives?|shows?|forces?|has)\b[\s\S]{0,120}\b(?:so|therefore|meaning|means?|count|counts?|fits?|becomes?)\b/i,
    /\b(?:grid|receipt|quote|checklist|graph|drawing|scale|balance|table|clipboard)\b[\s\S]{0,120}\b(?:says|shows|asks|forces|makes|has to|gives)\b/i,
    /\b(?:old|earlier|first)\s+(?:square|line|claim|frame|wording|shortcut)\b[\s\S]{0,120}\b(?:fits|becomes?|turns into|has to|should)\b/i,
    /\b(?:columns?|rows?|across|down)\b[\s\S]{0,120}\b(?:so|therefore|means?|makes?|gives?|shows?|forces?)\b/i,
    /\b(?:better|instead)\s+to\s+(?:suppose|start|frame|read|treat|ask|follow)\b/i,
    /\b(?:better|stronger|sharper)\s+(?:start|starting point)\s+(?:is|uses?)\b/i,
    /\b(?:better|sharper)\s+(?:split|test|question|frame|framing|reading)\s+(?:is|asks?)\b/i,
    /\b(?:rig|case|map|table|model|problem|scene)\s+is\s+asking\b[\s\S]{0,120}\b(?:where|whether|how|what)\b/i,
    /\b(?:new|better|revised)\s+version\s+should\s+say\b/i,
    /\bshould\s+(?:maybe\s+)?be\s+(?:marked|read|treated)\s+first\s+as\b/i,
    /\b(?:question|test)\s+is\s+not\b[\s\S]{0,120}\bbut\s+(?:whether|if)\b/i,
    /\bnow\s+the\s+question\s+is\s+whether\b/i,
    /\b(?:breaks?|interrupts?)\s+the\s+simple\s+story\b/i,
    /\bwrite\s+this\s+as\b/i,
    /\b(?:result|claim|summary|importance)\b[\s\S]{0,90}\bdepends on\b/i,
    /\b(?:clear|visible|visibility)\b[\s\S]{0,80}\b(?:mean|means?)\b[\s\S]{0,80}\b(?:absent|present|visible)\b/i,
    /\bnot\s+just\s+water\b[\s\S]{0,120}\b(?:solution|balance|salt)\b/i,
    /\bbalance\b[\s\S]{0,80}\b(?:weighs|measures|carries)\b[\s\S]{0,60}\bsalt\b/i,
    /\b(?:more like|better as|read from|looking back)\b/i,
    /\bread\s+it\s+as\b/i,
    /\bsplit\s+(?:tag|frame|claim|reading)\b/i,
    /\bpart\b[\s\S]{0,80}\bpart\b/i,
    /\b(?:maybe|now)\b[\s\S]{0,100}\b(?:is|becomes?)\s+the\s+(?:pattern|rule)\b/i,
    /\barea\s+is\b[\s\S]{0,100}\bacross\b[\s\S]{0,100}\bdown\b/i,
    /\b(?:effect size|estimate|interval)\b[\s\S]{0,120}\b(?:has|have|needs?|need)\s+to\s+show\b/i,
    /\b(?:it|that|this)\s+(?:should|has to|needs? to)\s+(?:start|read|say|show|lead)\b/i,
    /\bmore\b[\s\S]{0,40}\b(?:may|can)\s+mean\b/i,
    /\bwith\b[\s\S]{0,120}\bbalance\b[\s\S]{0,80}\b(?:stay|stays|settle|shows?)\b/i,
    /\bI\s+think\b[\s\S]{0,120}\b(?:has not|hasn't|is not|isn't)\b[\s\S]{0,80}\b(?:vanished|gone|absent|not there)\b/i,
    /\b(?:before\s+(?:I\s+)?(?:put|sign|release)|before release|before sign-?off)\b[\s\S]{0,180}\b(?:need|has to|want|run|show|prove|hold|release)\b/i,
    /\b(?:if\s+(?:it|the|that)|then)\b[\s\S]{0,140}\b(?:I\s+)?(?:do not|don['’]?t|can['’]?t|cannot)\b[\s\S]{0,90}\b(?:release|sign|sign off|clear)\b/i,
  ].some((pattern) => pattern.test(learnerText));
}

function reframeMatchStats(anchor, learnerText) {
  const revoice = revoiceMatchStats(anchor, learnerText);
  const problemNamed = namesEarlierFramingProblem(learnerText);
  const replacementNamed = replacesEarlierFraming(learnerText);
  return {
    ...revoice,
    revoice_compliant: revoice.compliant,
    problem_named: problemNamed,
    replacement_named: replacementNamed,
    compliant: revoice.compliant && problemNamed && replacementNamed,
  };
}

function reframeComplianceFailures(turns) {
  const failures = [];
  for (let i = 0; i < turns.length; i++) {
    const cue = turns[i];
    if (cue.role !== 'STAGE' || !isReframeCueText(cue.text)) {
      continue;
    }
    const anchor = extractRevisitAnchor(cue.text);
    const learner = turns.slice(i + 1).find((turn) => turn.role !== 'STAGE');
    const stats = reframeMatchStats(anchor, learner?.role === 'LEARNER' ? learner.text : '');
    if (anchor && learner?.role === 'LEARNER' && stats.compliant) continue;
    const missing = [];
    if (!stats.revoice_compliant) missing.push('revoice');
    if (!stats.problem_named) missing.push('framing_problem');
    if (!stats.replacement_named) missing.push('replacement_framing');
    failures.push({
      stage_turn_number: cue.turnNumber ?? i + 1,
      learner_turn_number: learner?.turnNumber ?? null,
      reason: !anchor
        ? 'missing_anchor'
        : learner?.role !== 'LEARNER'
          ? 'missing_followup_learner'
          : 'missing_reframe_consequence',
      missing,
      ...stats,
    });
  }
  return failures;
}

// External drama only: each trace turn (phase tutor|learner) → ROLE: text, in
// conversational order. internalDeliberation is dropped here (held out separately).
//
// restoreLeakedEgo (reclean only): an early build promoted a superego *verdict*
// addressed to the ego ("APPROVED. Ship it as written…") into the public tutor
// turn. The fixed engine keeps the ego draft whenever the superego's IMPROVED
// block opens with "approved"; this re-derives that same choice offline from the
// held-out trace, reclaiming the correct turn without re-calling any LLM.
function externalTurns(trace, { restoreLeakedEgo = false, includeStageDirections = true } = {}) {
  const out = [];
  const seenOpening = (trace.turns || []).some(
    (t) => t.phase === 'director' && Number(t.turnNumber) === 0 && String(t.externalMessage || '').trim(),
  );
  const pushStage = (text, turnNumber = null) => {
    const stageText = publicStageDirectionText(text);
    if (stageText) out.push({ role: 'STAGE', text: stageText, turnNumber });
  };
  if (includeStageDirections) {
    pushStage(publicReaderContextText(trace.directorPlan), 0);
  }
  if (includeStageDirections && trace.directorPlan?.scene_opening && !seenOpening) {
    pushStage(trace.directorPlan.scene_opening, 0);
  }
  for (const t of trace.turns || []) {
    if (includeStageDirections && t.phase === 'director' && t.externalMessage && String(t.externalMessage).trim()) {
      pushStage(t.externalMessage, t.turnNumber);
      continue;
    }
    if ((t.phase === 'tutor' || t.phase === 'learner') && t.externalMessage && String(t.externalMessage).trim()) {
      let text = String(t.externalMessage).trim();
      if (restoreLeakedEgo && t.phase === 'tutor' && /^\s*approved\b/i.test(text)) {
        const ego = (t.internalDeliberation || []).find((d) => d.role === 'ego');
        if (ego && String(ego.content).trim()) text = String(ego.content).trim();
      }
      out.push({ role: t.phase === 'tutor' ? 'TUTOR' : 'LEARNER', text, turnNumber: t.turnNumber });
    }
  }
  return out;
}

// One held-out key entry. Single source so the generate path and the resume-skip
// path can never drift (design hypotheses from the spec, counts from the turns).
function hasBlockingQualityWarnings(qualityWarnings = []) {
  return qualityWarnings.some((warning) => warning.severity !== 'info');
}

function keyItemFor(d, nTutor, nLearner, qualityWarnings = []) {
  const blocked = hasBlockingQualityWarnings(qualityWarnings);
  return {
    drama_id: d.id,
    discipline: d.discipline,
    condition: d.condition,
    pedagogical_approach: d.pedagogical_approach || d._pedagogicalApproach?.id || null,
    pedagogical_family: d._pedagogicalApproach?.family || null,
    dialogue_approach: d.dialogue_approach || d._dialogueApproach?.id || null,
    dialogue_family: d._dialogueApproach?.family || null,
    stage_direction_policy: stageDirectionPolicyFor(d),
    stage_direction_style: stageDirectionStyleFor(d)?.id || null,
    tutor_profile: d.tutor_profile,
    learner_profile: d.learner_profile,
    persona: d.persona,
    intended_tutor_character: d.intended_tutor_character,
    intended_lean: d.intended_lean,
    dramatic_shape: d.dramatic_shape,
    evaluation_role: d.evaluation_role || null,
    baseline_control_class: d.baseline_control_class || null,
    organic_reversal_risk: d.organic_reversal_risk || null,
    baseline_control_note: d.baseline_control_note || null,
    n_tutor_turns: nTutor,
    n_learner_turns: nLearner,
    director_mode: d._directorMode || null,
    director_variation_key: d._directorVariationKey || null,
    director_revisit_cue: Boolean(d._directorRevisitPolicy && d._directorRevisitPolicy !== 'none'),
    director_revisit_policy: d._directorRevisitPolicy || 'none',
    director_revisit_anchor:
      d._directorRevisitPolicy && d._directorRevisitPolicy !== 'none' ? d._directorRevisitAnchor || 'latest' : null,
    tutor_adaptation_policy: d._tutorAdaptationPolicy || d._directorPlan?.tutor_adaptation_policy || 'none',
    opening_speaker: d._directorPlan?.opening_speaker || null,
    ending_speaker: d._directorPlan?.ending_speaker || null,
    quality_status: blocked ? 'review_before_scoring' : 'ok',
    quality_warnings: qualityWarnings,
  };
}

function transcriptReframesAnchor(anchor, turns = []) {
  if (!anchor) return false;
  return turns.some((turn) => turn.role === 'LEARNER' && reframeMatchStats(anchor, turn.text).compliant);
}

function transcriptLooselyReframesAfterDowngrade(anchor, turns = []) {
  if (!anchor) return false;
  return turns.some((turn) => {
    if (turn.role !== 'LEARNER') return false;
    const learnerText = String(turn.text || '');
    if (!namesEarlierFramingProblem(learnerText) || !replacesEarlierFraming(learnerText)) return false;
    return true;
  });
}

function reframeDowngradeFailures(traceTurns = [], turns = []) {
  return traceTurns.flatMap((turn, idx) => {
    const cue = turn?.directorCue;
    if (turn?.phase !== 'director' || cue?.requestedRevisitPolicy !== 'reframe' || cue?.revisitPolicy === 'reframe') {
      return [];
    }
    if (transcriptReframesAnchor(cue.anchorQuote, turns)) return [];
    if (transcriptLooselyReframesAfterDowngrade(cue.anchorQuote, turns)) return [];
    return [
      {
        stage_turn_number: turn.turnNumber ?? idx + 1,
        requested_policy: cue.requestedRevisitPolicy,
        applied_policy: cue.revisitPolicy || null,
        anchor_gate: cue.reframeAnchorGate || null,
        revisit_anchor: cue.revisitAnchor || null,
        anchor_quote: cue.anchorQuote || null,
      },
    ];
  });
}

const NO_CUE_REFRAME_LEAK_PATTERNS = [
  /\bframing problem\b/i,
  /\breframe\s*:/i,
  /\brefram(?:e|ed|ing)\b/i,
  /\b(?:read|reads|reading)\s+(?:it|that|this|the line|the claim)\s+as\b/i,
  /\bthat still stands\b/i,
  /\bI was reading\b/i,
  /\bI made it sound\b/i,
  /\bthe old (?:mistake|frame|claim|line)\b/i,
  /\bold (?:answer|version|way|thinking)\b/i,
  /\bthe mistake was\b/i,
  /\bnew frame\b/i,
  /\bnew (?:answer|version|way|thinking)\b/i,
  /\breplacement framing\b/i,
  /\bI (?:thought|was thinking)\b[\s\S]{0,100}\bbut now\b/i,
  /\b(?:earlier|before),?\s+I\b[\s\S]{0,100}\b(?:thought|treated|used|called|made|read|framed)\b/i,
  /\bmy earlier\b[\s\S]{0,80}\b(?:answer|line|claim|wording|thinking|version)\b/i,
  /\bwhat I said\b[\s\S]{0,80}\b(?:made|treated|read|framed|sounded|meant)\b/i,
  /\bI (?:was |kept )?(?:treating|using|calling|making)\b[\s\S]{0,80}\b(?:as|like)\b/i,
  /\b(?:same|matching|position|slot|word|number|label|bracket|box|field)\b[\s\S]{0,80}\btrap\b/i,
  /\btrap\b[\s\S]{0,80}\b(?:same|matching|position|slot|word|number|label|bracket|box|field)\b/i,
  /\b(?:pull|pulls|pulled|pulling)\s+(?:me|my eye|my attention)\b[\s\S]{0,100}\b(?:but|so|because|still|now)\b/i,
];

function stripPublicWrappingQuotes(text) {
  const trimmed = splitLeadingActionAsides(String(text || '').trim()).speech;
  if (
    (trimmed.startsWith('"') && trimmed.endsWith('"')) ||
    (trimmed.startsWith('“') && trimmed.endsWith('”')) ||
    (trimmed.startsWith("'") && trimmed.endsWith("'")) ||
    (trimmed.startsWith('‘') && trimmed.endsWith('’'))
  ) {
    return trimmed.slice(1, -1).trim();
  }
  return trimmed;
}

const INTRUSIVE_STAGE_DIRECTION_PATTERNS = [
  /\b(?:the learner|the tutor|the next speaker)\s+must\b/i,
  /\b(?:the learner|the tutor|the next reply)\s+has to\b/i,
  /\b(?:do not|don't)\s+(?:let|have|ask|allow)\b/i,
  /\b(?:must|should)\s+(?:revoice|respond|answer|name|replace|quote)\b/i,
  /\bpublic speech\b/i,
  /\b(?:generator|generated|hidden review|role labels?|scene card|recognition label)\b/i,
  /\b(?:the director|director)\b[\s\S]{0,80}\b(?:intends|wants|requires|forces|instructs)\b/i,
];

function intrusiveStageDirectionFailures(turns) {
  return turns
    .map((turn, idx) => ({ ...turn, ordinal: idx + 1 }))
    .filter((turn) => turn.role === 'STAGE')
    .flatMap((turn) => {
      if (isAnchoredRevisitCueText(turn.text)) return [];
      const matched = INTRUSIVE_STAGE_DIRECTION_PATTERNS.find((pattern) => pattern.test(turn.text));
      if (!matched) return [];
      return [
        {
          turn_number: turn.turnNumber ?? turn.ordinal,
          matched_pattern: String(matched),
          excerpt: turn.text.slice(0, 240),
        },
      ];
    });
}

function noCueReframeLeakageFailures(turns) {
  const learnerTurns = turns
    .map((turn, idx) => ({ ...turn, ordinal: idx + 1 }))
    .filter((turn) => turn.role === 'LEARNER');
  return learnerTurns.flatMap((turn, idx) => {
    if (idx < 2) return [];
    const publicSpeech = stripPublicWrappingQuotes(turn.text);
    const matched = NO_CUE_REFRAME_LEAK_PATTERNS.find((pattern) => pattern.test(publicSpeech));
    const selfQuote = /(?:^|\s)["“][\s\S]{12,}?["”]/.test(publicSpeech.trim());
    const quotesPriorLearner =
      selfQuote &&
      learnerTurns
        .slice(0, idx)
        .some((prior) => revoiceMatchStats(stripPublicWrappingQuotes(prior.text), publicSpeech).compliant);
    if (!matched && !quotesPriorLearner) return [];
    return [
      {
        learner_turn_number: idx + 1,
        turn_number: turn.turnNumber ?? turn.ordinal,
        matched_pattern: matched ? String(matched) : 'self_quote_of_prior_learner_turn',
        excerpt: turn.text.slice(0, 240),
      },
    ];
  });
}

// Hardcoded stock-fallback the interaction engine emits when
// extractTutorMessage() cannot parse a visible message out of the model output
// (services/learnerTutorInteractionEngine.js ~line 1744). Detecting it lets us
// flag silent parser-failure → fallback chains as a quality warning instead of
// letting them sail through scoring as if they were real tutor turns. Match is
// trimmed-equality so trailing whitespace doesn't hide it.
const TUTOR_STOCK_FALLBACK_TEXT =
  "I see what you're saying. Let me think about that for a moment. Could you tell me more about what's confusing you?";

function tutorStockFallbackFailures(turns) {
  return turns
    .map((t, idx) => ({ ...t, ordinal: idx + 1 }))
    .filter((t) => t.role === 'TUTOR' && String(t.text || '').trim() === TUTOR_STOCK_FALLBACK_TEXT)
    .map((t) => ({
      turn_number: t.turnNumber ?? t.ordinal,
      excerpt: String(t.text || '').slice(0, 240),
    }));
}

function qualityWarningsFor({
  tid,
  dramaId,
  turns,
  removedNotes = [],
  traceTurns = [],
  directorPolicy = null,
  tutorAdaptationPolicy = null,
}) {
  const warnings = [];
  // Inspect the PUBLIC text (post stage-direction strip + neutralize), matching what
  // renderTranscript emits: internal-process language that is stripped before the
  // public transcript must not false-flag as a leak, and a wrapping quote must not
  // hide genuine mid-thought truncation. (EDRA FIX 3 — text parity with the rendered
  // public transcript; see notes/poetics/2026-05-28-edra-m3-surgery-spec.md FIX 3.)
  const publicTurns = (turns || []).map((t) => ({ ...t, text: stripStageDirections(neutralize(t.text)).text }));
  const internalLeakPattern =
    /\b(?:Superego|same Ego|the Ego|Director Scene Card|scene card|review process|internal review)\b/i;
  const leakedTurns = publicTurns
    .map((t, idx) => ({ ...t, ordinal: idx + 1 }))
    .filter((t) => internalLeakPattern.test(t.text));
  if (leakedTurns.length) {
    warnings.push({
      code: 'possible_internal_process_leak',
      severity: 'warning',
      count: leakedTurns.length,
      turn_numbers: leakedTurns.map((t) => t.turnNumber ?? t.ordinal),
      recommended_action: 'inspect_full_transcript_and_regenerate_before_scoring',
    });
  }
  const intrusiveStageDirections = intrusiveStageDirectionFailures(turns);
  if (intrusiveStageDirections.length) {
    warnings.push({
      code: 'intrusive_stage_direction',
      severity: 'warning',
      count: intrusiveStageDirections.length,
      failures: intrusiveStageDirections,
      turn_numbers: intrusiveStageDirections.map((failure) => failure.turn_number),
      recommended_action: 'regenerate_with_public_scene_material_not_role_instruction',
    });
  }
  const truncatedLearnerTurns = publicTurns
    .map((t, idx) => ({ ...t, ordinal: idx + 1 }))
    .filter(
      (t, idx) =>
        t.role === 'LEARNER' &&
        isTruncated(stripWrappingSpeechQuotes(t.text)) &&
        !previousStageAllowsFragment(publicTurns, idx),
    );
  if (truncatedLearnerTurns.length) {
    warnings.push({
      code: 'possibly_truncated_learner_turn',
      severity: 'warning',
      count: truncatedLearnerTurns.length,
      turn_numbers: truncatedLearnerTurns.map((t) => t.turnNumber ?? t.ordinal),
      recommended_action: 'regenerate_or_exclude_before_scoring',
    });
  }
  const nLearner = turns.filter((t) => t.role === 'LEARNER').length;
  if (nLearner < 2) {
    warnings.push({
      code: 'too_few_learner_turns',
      severity: 'warning',
      count: nLearner,
      minimum: 2,
      recommended_action: 'regenerate_or_exclude_before_scoring',
    });
  }
  const stockFallbackTutorTurns = tutorStockFallbackFailures(turns);
  if (stockFallbackTutorTurns.length) {
    warnings.push({
      code: 'tutor_stock_fallback',
      severity: 'warning',
      count: stockFallbackTutorTurns.length,
      failures: stockFallbackTutorTurns,
      turn_numbers: stockFallbackTutorTurns.map((failure) => failure.turn_number),
      recommended_action: 'regenerate_or_exclude_before_scoring',
    });
  }
  const revoiceFailures = revoiceComplianceFailures(turns);
  if (revoiceFailures.length) {
    warnings.push({
      code: 'revoice_cue_not_revoiced',
      severity: 'warning',
      count: revoiceFailures.length,
      failures: revoiceFailures,
      turn_numbers: revoiceFailures.map((failure) => failure.learner_turn_number || failure.stage_turn_number),
      recommended_action: 'regenerate_or_exclude_before_scoring',
    });
  }
  const reframeFailures = reframeComplianceFailures(turns);
  if (reframeFailures.length) {
    warnings.push({
      code: 'reframe_cue_not_reframed',
      severity: 'warning',
      count: reframeFailures.length,
      failures: reframeFailures,
      turn_numbers: reframeFailures.map((failure) => failure.learner_turn_number || failure.stage_turn_number),
      recommended_action: 'regenerate_or_exclude_before_scoring',
    });
  }
  const downgradedReframes = reframeDowngradeFailures(traceTurns, turns);
  if (downgradedReframes.length) {
    warnings.push({
      code: 'reframe_cue_downgraded',
      severity: 'warning',
      count: downgradedReframes.length,
      failures: downgradedReframes,
      turn_numbers: downgradedReframes.map((failure) => failure.stage_turn_number),
      recommended_action: 'regenerate_with_eligible_reframe_anchor_or_exclude_before_scoring',
    });
  }
  if (directorPolicy === 'none' && !String(tutorAdaptationPolicy || '').includes('peripeteia')) {
    const noCueLeaks = noCueReframeLeakageFailures(turns);
    if (noCueLeaks.length) {
      warnings.push({
        code: 'no_cue_reframe_leakage',
        severity: 'warning',
        count: noCueLeaks.length,
        failures: noCueLeaks,
        turn_numbers: noCueLeaks.map((failure) => failure.turn_number),
        recommended_action: 'regenerate_no_cue_arm_or_move_item_to_boundary_suite_before_scoring',
      });
    }
    const closureLeaks = noCuePrematureClosureFailures(turns);
    if (closureLeaks.length) {
      warnings.push({
        code: 'no_cue_premature_closure',
        severity: 'warning',
        count: closureLeaks.length,
        failures: closureLeaks,
        turn_numbers: closureLeaks.map((failure) => failure.turn_number),
        recommended_action: 'regenerate_no_cue_arm_or_move_item_to_boundary_suite_before_scoring',
      });
    }
  }
  if (removedNotes.length) {
    warnings.push({
      code: 'stage_direction_leak_stripped',
      severity: 'info',
      count: removedNotes.length,
      artifact: `${tid}.stripped.json`,
      recommended_action: 'audit_stripped_notes',
    });
  }
  return warnings.map((warning) => ({ ...warning, tid, drama_id: dramaId }));
}

function formatQualityWarning(warning) {
  if (warning.code === 'possibly_truncated_learner_turn') {
    return `${warning.tid} (${warning.drama_id}): ${warning.count} possibly-truncated learner turn(s) — regenerate or exclude before scoring`;
  }
  if (warning.code === 'too_few_learner_turns') {
    return `${warning.tid} (${warning.drama_id}): only ${warning.count} learner turn(s) — too short to judge recohering`;
  }
  if (warning.code === 'stage_direction_leak_stripped') {
    return `${warning.tid} (${warning.drama_id}): stripped ${warning.count} stage-direction leak(s) — see held-out ${warning.artifact}`;
  }
  if (warning.code === 'possible_internal_process_leak') {
    return `${warning.tid} (${warning.drama_id}): ${warning.count} public turn(s) may leak internal process — inspect/regenerate before scoring`;
  }
  if (warning.code === 'intrusive_stage_direction') {
    return `${warning.tid} (${warning.drama_id}): ${warning.count} stage direction(s) read as role instruction rather than public scene material — regenerate or reclean before scoring`;
  }
  if (warning.code === 'revoice_cue_not_revoiced') {
    return `${warning.tid} (${warning.drama_id}): ${warning.count} revoice cue(s) were not visibly revoiced — regenerate or exclude before scoring`;
  }
  if (warning.code === 'reframe_cue_not_reframed') {
    return `${warning.tid} (${warning.drama_id}): ${warning.count} reframe cue(s) did not expose the public reframing consequence — regenerate or exclude before scoring`;
  }
  if (warning.code === 'reframe_cue_downgraded') {
    return `${warning.tid} (${warning.drama_id}): ${warning.count} requested reframe cue(s) were downgraded by the anchor gate — regenerate or exclude before scoring`;
  }
  if (warning.code === 'no_cue_reframe_leakage') {
    return `${warning.tid} (${warning.drama_id}): ${warning.count} no-cue learner turn(s) visibly self-reframed — regenerate or move to boundary suite`;
  }
  if (warning.code === 'no_cue_premature_closure') {
    return `${warning.tid} (${warning.drama_id}): ${warning.count} no-cue learner turn(s) used premature closure/insight language — regenerate or move to boundary suite`;
  }
  if (warning.code === 'tutor_stock_fallback') {
    return `${warning.tid} (${warning.drama_id}): ${warning.count} tutor turn(s) used the empty-response stock fallback — parser failed to extract a visible message; regenerate or exclude before scoring`;
  }
  return `${warning.tid} (${warning.drama_id}): ${warning.code}`;
}

function sha256Short(text) {
  return createHash('sha256')
    .update(String(text || ''))
    .digest('hex')
    .slice(0, 16);
}

function buildCallProvenance({
  agentRole,
  backend,
  cli,
  model,
  reasoningEffort,
  systemPrompt,
  userPrompt,
  latencyMs,
  args,
}) {
  return {
    agentRole,
    backend,
    cli,
    model,
    reasoningEffort: reasoningEffort || null,
    latencyMs,
    promptHashes: {
      system: sha256Short(systemPrompt),
      user: sha256Short(userPrompt),
      combined: sha256Short(`${systemPrompt}\n\n---\n\n${userPrompt}`),
    },
    args,
  };
}

function withUsage(result, { provider, model, provenance }) {
  return {
    content: result.content,
    usage: { inputTokens: 0, outputTokens: 0 },
    provider,
    model,
    latencyMs: result.latencyMs,
    generationId: `drama-${provenance.backend}-${provenance.agentRole}-${provenance.promptHashes.combined}`,
    provenance,
    apiPayload: { provenance },
  };
}

// ── claude-code CLI bridge (lifted from realLLM.js:callClaudeCli) ────────────

// High reasoning tiers (xhigh/max) on heavy prompts (e.g. the director's scene
// card) can take ~100s+ per call; GEN_DRAMAS_CLAUDE_TIMEOUT_MS raises the per-call
// ceiling for those runs without changing the default.
const CLAUDE_CLI_TIMEOUT_MS = Number(process.env.GEN_DRAMAS_CLAUDE_TIMEOUT_MS) || 360_000;
const CLI_TRACE = process.env.GEN_DRAMAS_CLI_TRACE === '1';

function callClaudeCli(systemPrompt, userPrompt, model, effort, role) {
  const start = Date.now();
  return new Promise((resolve, reject) => {
    // --system-prompt REPLACES the default system prompt → suppresses ambient
    // output-style additions (the "★ Insight" block) that would pollute turns.
    const args = ['-p', '-', '--output-format', 'text', '--system-prompt', systemPrompt];
    if (model) args.push('--model', model);
    // --effort <low|medium|high|xhigh|max>: claude CLI reasoning tier. Unset → CLI
    // default (preserves the original default-effort claude arm); pinned → recorded
    // in provenance below so the run carries its own reasoning setting.
    if (effort) args.push('--effort', effort);
    const env = { ...process.env };
    delete env.CLAUDE_CODE;
    delete env.CLAUDECODE;
    // The run's --effort flag is the single source of truth for the reasoning tier.
    // A parent session may export CLAUDE_CODE_EFFORT_LEVEL (e.g. =max); left in the
    // child env it silently overrides --effort, so the run *records* xhigh but
    // *executes* max — both a latency surprise and a provenance lie. Strip it so
    // behaviour and provenance agree.
    delete env.CLAUDE_CODE_EFFORT_LEVEL;
    delete env.ANTHROPIC_API_KEY; // force subscription window, not metered API
    delete env.ANTHROPIC_AUTH_TOKEN;
    const child = spawn('claude', args, { stdio: ['pipe', 'pipe', 'pipe'], env });
    let out = '';
    let err = '';
    const to = setTimeout(() => {
      try {
        child.kill('SIGKILL');
      } catch (_) {
        /* gone */
      }
      reject(new Error(`claude CLI timed out after ${CLAUDE_CLI_TIMEOUT_MS}ms (role=${role}, outBytes=${out.length})`));
    }, CLAUDE_CLI_TIMEOUT_MS);
    child.stdout.on('data', (d) => (out += d));
    child.stderr.on('data', (d) => (err += d));
    child.on('error', (e) => {
      clearTimeout(to);
      reject(e);
    });
    child.on('close', (code) => {
      clearTimeout(to);
      if (code !== 0) {
        reject(new Error(err.trim() || out.trim() || `claude CLI exited ${code} (role=${role})`));
      } else {
        const latencyMs = Date.now() - start;
        if (CLI_TRACE) console.error(`[gen-cli] role=${role} ${latencyMs}ms ${out.length}b`);
        resolve({
          content: out.trim(),
          latencyMs,
          provenance: buildCallProvenance({
            agentRole: role,
            backend: 'claude',
            cli: 'claude',
            model: model || 'default',
            reasoningEffort: effort || null,
            systemPrompt,
            userPrompt,
            latencyMs,
            args: [
              '-p',
              '-',
              '--output-format',
              'text',
              '--system-prompt',
              `<sha256:${sha256Short(systemPrompt)}>`,
              ...(model ? ['--model', model] : []),
              ...(effort ? ['--effort', effort] : []),
            ],
          }),
        });
      }
    });
    child.stdin.write(userPrompt);
    child.stdin.end();
  });
}

// ── codex exec CLI bridge (mirrors score-poetics-calibration.js:callCodex) ───
// codex has NO system channel, so system + user are folded into one stdin prompt.
// It uses codex's stored login — a SEPARATE quota pool from the Max-plan claude
// CLI — so a codex generator never contends with a concurrent claude generator,
// and generator≠critic holds (codex-authored dramas are judged by claude-code).
const CODEX_CLI_TIMEOUT_MS = 360_000;
// Reasoning tier is pinned EXPLICITLY here rather than inherited from
// ~/.codex/config.toml, so a run records its own settings and can't silently
// drift if personal config is edited between runs. `model_reasoning_effort` is
// parsed by codex as TOML, hence the embedded quotes (→ string "xhigh").
// CODEX_MODEL stays null by default: we still avoid hardcoding a model name that
// goes stale (codex picks its configured default), but it's overridable for a
// fully-pinned reproducible run. xhigh is gpt-5.x's top tier.
const CODEX_REASONING_EFFORT = process.env.CODEX_REASONING_EFFORT || 'xhigh';
const CODEX_MODEL = process.env.CODEX_MODEL || null;

function callCodexExec(systemPrompt, userPrompt, role) {
  const start = Date.now();
  return new Promise((resolve, reject) => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'gen-codex-'));
    const outFile = path.join(tmpDir, 'out.txt');
    const cleanup = () => {
      try {
        fs.rmSync(tmpDir, { recursive: true, force: true });
      } catch (_) {
        /* gone */
      }
    };
    // -s read-only + --ephemeral + per-call -C tmpDir: codex cannot touch the repo.
    const args = ['exec', '--skip-git-repo-check', '--ephemeral', '-s', 'read-only', '-C', tmpDir, '--color', 'never'];
    if (CODEX_MODEL) args.push('-m', CODEX_MODEL);
    if (CODEX_REASONING_EFFORT) args.push('-c', `model_reasoning_effort="${CODEX_REASONING_EFFORT}"`);
    args.push('-o', outFile, '-');
    const child = spawn('codex', args, { stdio: ['pipe', 'pipe', 'pipe'] });
    let err = '';
    const to = setTimeout(() => {
      try {
        child.kill('SIGKILL');
      } catch (_) {
        /* gone */
      }
      cleanup();
      reject(new Error(`codex CLI timed out after ${CODEX_CLI_TIMEOUT_MS}ms (role=${role})`));
    }, CODEX_CLI_TIMEOUT_MS);
    child.stderr.on('data', (d) => (err += d));
    child.on('error', (e) => {
      clearTimeout(to);
      cleanup();
      reject(e);
    });
    child.on('close', (code) => {
      clearTimeout(to);
      let out = '';
      try {
        out = fs.readFileSync(outFile, 'utf8');
      } catch (_) {
        /* missing */
      }
      cleanup();
      if (code !== 0 && !out.trim()) {
        reject(new Error(err.trim() || `codex CLI exited ${code} (role=${role})`));
      } else {
        const latencyMs = Date.now() - start;
        if (CLI_TRACE) console.error(`[gen-cli] role=${role} (codex) ${latencyMs}ms ${out.length}b`);
        resolve({
          content: out.trim(),
          latencyMs,
          provenance: buildCallProvenance({
            agentRole: role,
            backend: 'codex',
            cli: 'codex exec',
            model: CODEX_MODEL || 'config-default',
            reasoningEffort: CODEX_REASONING_EFFORT || null,
            systemPrompt,
            userPrompt,
            latencyMs,
            args,
          }),
        });
      }
    });
    child.stdin.write(`${systemPrompt}\n\n---\n\n${userPrompt}`);
    child.stdin.end();
  });
}

// ── gemini CLI bridge: now routes through `agy` (~/.local/bin/agy) ───────────
// Used by --generator gemini to triangulate the author-confound finding: the
// 022408Z 2×2 left us unable to distinguish "Sonnet picks up real recognitive
// form" from "Sonnet over-credits Claude-family prose." A Gemini-family author
// is arms-length from Anthropic-family critics.
//
// `agy` superseded the upstream `gemini` CLI on 2026-05-28 — same family, higher
// quota, claude-code-style flag surface (--print / --print-timeout /
// --dangerously-skip-permissions / --add-dir). The model is bound at the agy
// install layer (no -m flag); GEMINI_MODEL is therefore a provenance label, not
// a runtime selector. Confirmed via `echo ... | agy --print` → "gemini-3.5-flash".
const GEMINI_CLI_TIMEOUT_MS = 600_000;
const GEMINI_MODEL = process.env.GEMINI_MODEL || 'gemini-3.5-flash';
const AGY_BIN = process.env.AGY_BIN || path.join(os.homedir(), '.local/bin/agy');

function callGeminiCli(systemPrompt, userPrompt, role) {
  const start = Date.now();
  return new Promise((resolve, reject) => {
    // cwd: tmpDir keeps agy from auto-loading the repo's CLAUDE.md or any other
    // project context — the bridge is meant to produce arm's-length transcripts.
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'gen-agy-'));
    const cleanup = () => {
      try {
        fs.rmSync(tmpDir, { recursive: true, force: true });
      } catch (_) {
        /* gone */
      }
    };
    // --print + stdin: agy reads the prompt from stdin in --print mode.
    // --print-timeout 10m matches our wall-clock ceiling so the CLI cannot
    // declare success before we time out the spawn.
    // --dangerously-skip-permissions auto-approves any tool gate so a single
    // background tool prompt cannot stall the batch (same role --yolo played
    // for the deprecated gemini CLI). The poetics prompts don't invoke tools
    // in normal operation; this is belt-and-braces against a stalled batch.
    const args = ['--print', '--print-timeout', '10m', '--dangerously-skip-permissions'];
    const env = { ...process.env };
    delete env.CLAUDE_CODE;
    delete env.CLAUDECODE;
    const child = spawn(AGY_BIN, args, { stdio: ['pipe', 'pipe', 'pipe'], env, cwd: tmpDir });
    let out = '';
    let err = '';
    const to = setTimeout(() => {
      try {
        child.kill('SIGKILL');
      } catch (_) {
        /* gone */
      }
      cleanup();
      reject(new Error(`agy CLI timed out after ${GEMINI_CLI_TIMEOUT_MS}ms (role=${role}, outBytes=${out.length})`));
    }, GEMINI_CLI_TIMEOUT_MS);
    child.stdout.on('data', (d) => (out += d));
    child.stderr.on('data', (d) => (err += d));
    child.on('error', (e) => {
      clearTimeout(to);
      cleanup();
      reject(e);
    });
    child.on('close', (code) => {
      clearTimeout(to);
      cleanup();
      if (code !== 0) {
        reject(new Error(err.trim() || out.trim() || `agy CLI exited ${code} (role=${role})`));
      } else {
        const latencyMs = Date.now() - start;
        if (CLI_TRACE) console.error(`[gen-cli] role=${role} (agy/${GEMINI_MODEL}) ${latencyMs}ms ${out.length}b`);
        resolve({
          content: out.trim(),
          latencyMs,
          provenance: buildCallProvenance({
            agentRole: role,
            backend: 'gemini',
            cli: 'agy',
            model: GEMINI_MODEL,
            reasoningEffort: null,
            systemPrompt,
            userPrompt,
            latencyMs,
            args,
          }),
        });
      }
    });
    child.stdin.write(`${systemPrompt}\n\n---\n\n${userPrompt}`);
    child.stdin.end();
  });
}

// runInteraction's llmCall contract: (model, systemPrompt, messages, opts) →
// {content, usage}. We IGNORE the per-profile model and force claude-code.
function makeClaudeLlmCall(modelAlias, effort) {
  return async function claudeLlmCall(_model, systemPrompt, messages, opts = {}) {
    const userPrompt = (messages || []).map((m) => m.content).join('\n');
    const result = await callClaudeCli(systemPrompt, userPrompt, modelAlias, effort, opts.agentRole || 'gen');
    return withUsage(result, {
      provider: 'claude-code',
      model: `claude/${modelAlias || 'default'}${effort ? `@${effort}` : ''}`,
      provenance: result.provenance,
    });
  };
}

// Same contract via codex exec. The per-profile model is ignored; system +
// messages are folded by callCodexExec. By default the whole drama is one model
// (--generator codex), but a --role-map can route individual roles to codex while
// others go to claude (see makeRouterLlmCall).
function makeCodexLlmCall() {
  return async function codexLlmCall(_model, systemPrompt, messages, opts = {}) {
    const userPrompt = (messages || []).map((m) => m.content).join('\n');
    const result = await callCodexExec(systemPrompt, userPrompt, opts.agentRole || 'gen');
    return withUsage(result, {
      provider: 'codex-cli',
      model: `codex/${CODEX_MODEL || 'config-default'}@${CODEX_REASONING_EFFORT || 'default'}`,
      provenance: result.provenance,
    });
  };
}

// Same contract via gemini CLI. Used by --generator gemini.
function makeGeminiLlmCall() {
  return async function geminiLlmCall(_model, systemPrompt, messages, opts = {}) {
    const userPrompt = (messages || []).map((m) => m.content).join('\n');
    const result = await callGeminiCli(systemPrompt, userPrompt, opts.agentRole || 'gen');
    return withUsage(result, {
      provider: 'gemini-cli',
      model: `gemini/${GEMINI_MODEL}`,
      provenance: result.provenance,
    });
  };
}

// Deterministic stub for --mock: role-appropriate canned text, no cost. Proves
// the externalTurns→neutralize→write pipeline end-to-end without the CLI.
function makeMockLlmCall(backend = 'mock') {
  let n = 0;
  return async function mockLlmCall(_model, systemPrompt, messages, opts = {}) {
    n++;
    const role = opts.agentRole || 'agent';
    const userPrompt = (messages || []).map((m) => m.content).join('\n');
    const latencyMs = 0;
    const result = {
      content: `[mock ${backend}:${role} #${n}] This is a stand-in turn for wiring validation only.`,
      latencyMs,
      provenance: buildCallProvenance({
        agentRole: role,
        backend,
        cli: 'mock',
        model: `mock-${backend}`,
        reasoningEffort: null,
        systemPrompt,
        userPrompt,
        latencyMs,
        args: [],
      }),
    };
    return withUsage(result, {
      provider: `${backend}-mock`,
      model: `mock/${backend}`,
      provenance: result.provenance,
    });
  };
}

// ── per-role model routing ───────────────────────────────────────────────────
// The bilateral engine tags every llmCall with opts.agentRole (one of the five
// strings below). A --role-map lets DIFFERENT roles be authored by DIFFERENT
// models in the SAME drama — e.g. a Claude tutor drawing out a codex learner, or
// a cross-model superego (codex critiquing Claude's drafts). Resolution is
// most-specific-first: exact role > side (tutor|learner) > explicit default >
// the --generator fallback. NOTE: a mixed drama has no single "author", so the
// clean generator≠critic guarantee no longer holds end-to-end — pick the human/
// instrument critic deliberately (see the run's closing note).
const ROLE_ALIASES = {
  learner_ego_initial: 'learner_ego',
  learner_ego_revision: 'learner_ego',
};
const ROLE_NAMES = ['director', 'tutor_ego', 'tutor_superego', 'learner_ego', 'learner_superego'];
const ROLE_MAP_KEYS = new Set(['tutor', 'learner', 'default', ...ROLE_NAMES]);

function parseRoleMap(str) {
  const map = {};
  for (const pair of String(str)
    .split(',')
    .map((s) => s.trim())
    .filter(Boolean)) {
    const eq = pair.indexOf('=');
    if (eq < 1) throw new Error(`--role-map entry must be key=value (got "${pair}")`);
    const rawKey = pair.slice(0, eq).trim();
    const k = ROLE_ALIASES[rawKey] || rawKey;
    const v = pair.slice(eq + 1).trim();
    if (!ROLE_MAP_KEYS.has(k))
      throw new Error(`--role-map key "${rawKey}" not one of: ${[...ROLE_MAP_KEYS].join(', ')}`);
    if (v !== 'claude' && v !== 'codex')
      throw new Error(`--role-map value for "${k}" must be claude|codex (got "${v}")`);
    map[k] = v;
  }
  if (Object.keys(map).length === 0) throw new Error('--role-map is empty');
  return map;
}

function resolveBackend(agentRole, roleMap, fallback) {
  if (agentRole && roleMap[agentRole]) return roleMap[agentRole]; // exact role
  const side =
    agentRole && agentRole.startsWith('tutor')
      ? 'tutor'
      : agentRole && agentRole.startsWith('learner')
        ? 'learner'
        : null;
  if (side && roleMap[side]) return roleMap[side]; // tutor|learner side
  if (roleMap.default) return roleMap.default; // explicit default
  return fallback; // --generator
}

// Router llmCall: dispatch each role to its resolved backend. Under --mock both
// backends are the same stub, but the route decision is still computed + logged
// (GEN_DRAMAS_CLI_TRACE=1) so routing can be smoke-tested for free.
function makeRouterLlmCall({ roleMap, fallback, claudeModelAlias, claudeEffort, mock }) {
  const claudeBridge = mock ? makeMockLlmCall('claude') : makeClaudeLlmCall(claudeModelAlias, claudeEffort);
  const codexBridge = mock ? makeMockLlmCall('codex') : makeCodexLlmCall();
  const geminiBridge = mock ? makeMockLlmCall('gemini') : makeGeminiLlmCall();
  return async function routerLlmCall(model, systemPrompt, messages, opts = {}) {
    const backend = resolveBackend(opts.agentRole, roleMap, fallback);
    if (CLI_TRACE) console.error(`[gen-route] role=${opts.agentRole || '?'} → ${backend}`);
    const bridge = backend === 'codex' ? codexBridge : backend === 'gemini' ? geminiBridge : claudeBridge;
    return bridge(model, systemPrompt, messages, opts);
  };
}

// ── teaching-drama director ─────────────────────────────────────────────────
// The director is a scene-level author, not a tutor or learner. Its output is
// hidden from the clean public transcript and preserved in the full transcript.
// It varies scene setting, register, speaker order, direct-address budget, and
// scheduled "deus ex machina" cues that the next actor must absorb privately.
const VOICE_VARIANTS = [
  {
    locale: 'international academic English, compact and low idiom',
    register: 'seminar-table reserve; fewer direct second-person appeals',
    person_policy: 'Allow indirect third-person framing; avoid beginning every turn with I/you.',
  },
  {
    locale: 'British/Commonwealth classroom English',
    register: 'dry, clipped, lightly ironic but not sarcastic',
    person_policy: 'Prefer declarative turns and concrete examples over validation-first phrasing.',
  },
  {
    locale: 'workplace training room',
    register: 'adult learner, practical stakes, compressed speech',
    person_policy: 'Use first person only when the speaker is actually owning a claim.',
  },
  {
    locale: 'multilingual learner using plain English',
    register: 'direct, slightly elliptical, non-fluent but not caricatured',
    person_policy: 'Avoid fake dialect spelling; show register through syntax, brevity, and repair.',
  },
  {
    locale: 'rural/community college tutorial',
    register: 'plain-spoken, wary of abstractions, concrete objects first',
    person_policy: 'Limit "you" validation; make speakers point at the thing in the room.',
  },
  {
    locale: 'online asynchronous feedback thread',
    register: 'short posts, delayed replies, occasional quotation of prior text',
    person_policy: 'Allow quoted fragments and third-person reference to submitted work.',
  },
];

const SETTINGS = [
  'after class, with chairs already being stacked',
  'a workplace training session during a short break',
  'a community college tutoring desk with a queue forming nearby',
  'an online course comment thread after a marked exercise',
  'a museum/gallery education session with the object in view',
  'a lab bench conversation while equipment is being packed away',
];

const STAGE_DIRECTION_STYLES = [
  {
    id: 'bare_transcript',
    policies: ['none', 'none_except_required_cue'],
    prompt:
      'No ordinary visible stage direction. Let context be inferred from speech, quoted artifacts, timestamps, or task references.',
  },
  {
    id: 'scene_heading',
    policies: ['sparse', 'short'],
    prompt: 'Use a compact scene heading or situating line, closer to a script heading than explanatory narration.',
  },
  {
    id: 'object_business',
    policies: ['sparse', 'short', 'interventionist', 'rich'],
    prompt: 'Use one concrete object action or material arrangement that changes what the speakers can honestly say.',
  },
  {
    id: 'ambient_pressure',
    policies: ['sparse', 'short'],
    prompt:
      'Use time, queue, room, or institutional pressure as stage texture; avoid explaining the lesson through it.',
  },
  {
    id: 'placard_caption',
    policies: ['interventionist', 'rich'],
    prompt:
      'Use a public placard, caption, board note, or displayed rule that interrupts how the previous line is read.',
  },
  {
    id: 'thread_metadata',
    policies: ['sparse', 'short'],
    prompt: 'Use transcript/thread metadata such as edit markers, timestamps, quoted fragments, or a reopened comment.',
  },
  {
    id: 'choric_margin',
    policies: ['short', 'interventionist', 'rich'],
    prompt:
      'Use a brief margin voice, chorus-like room note, or institutional phrase as public scene material, not theory.',
  },
  {
    id: 'rich_scene_work',
    policies: ['rich'],
    prompt:
      'Use recurring physical scene detail across the exchange so context develops, without turning into hidden commentary.',
  },
];

const STAGE_DIRECTION_STYLE_BY_ID = new Map(STAGE_DIRECTION_STYLES.map((style) => [style.id, style]));

const DISCIPLINE_OBJECTS = {
  algebra: 'balance sketch',
  academic_writing: 'marked draft paragraph',
  biology: 'specimen tray',
  cartography: 'wall map',
  civic_science: 'survey table',
  clinical_training: 'checklist sheet',
  economics: 'price chart',
  engineering: 'prototype rig',
  environmental_science: 'field data table',
  geometry: 'squared grid',
  history: 'source packet',
  media_studies: 'annotated headline',
  medicine: 'case note',
  sociology: 'projected chart',
};

function loadApproachDatabase(filePath, kind) {
  if (!filePath) return { path: null, version: null, byId: new Map() };
  const doc = yaml.parse(fs.readFileSync(filePath, 'utf8')) || {};
  const byId = new Map();
  for (const entry of doc.approaches || []) {
    if (!entry?.id) throw new Error(`${kind} approach entry is missing id in ${filePath}`);
    if (byId.has(entry.id)) throw new Error(`duplicate ${kind} approach id "${entry.id}" in ${filePath}`);
    byId.set(entry.id, { ...entry, _kind: kind, _sourcePath: path.relative(WORKTREE_ROOT, filePath) });
  }
  return { path: filePath, version: doc.version || null, byId };
}

function loadApproachDatabases(args) {
  return {
    pedagogical: loadApproachDatabase(args.pedagogyDb, 'pedagogical'),
    dialogue: loadApproachDatabase(args.dialogueDb, 'dialogue'),
  };
}

function attachApproaches(d, databases) {
  if (d.pedagogical_approach) {
    const approach = databases.pedagogical.byId.get(d.pedagogical_approach);
    if (!approach) throw new Error(`drama ${d.id} references unknown pedagogical_approach: ${d.pedagogical_approach}`);
    d._pedagogicalApproach = approach;
  }
  if (d.dialogue_approach) {
    const approach = databases.dialogue.byId.get(d.dialogue_approach);
    if (!approach) throw new Error(`drama ${d.id} references unknown dialogue_approach: ${d.dialogue_approach}`);
    d._dialogueApproach = approach;
  }
  return d;
}

function approachSummaryForPrompt(approach) {
  if (!approach) return null;
  const keys = [
    'id',
    'family',
    'lineage',
    'medium',
    'core_move',
    'turn_shape',
    'stage_direction_policy',
    'stage_direction_style',
    'tutor_prompt',
    'learner_prompt',
    'director_prompt',
    'tutor_constraint',
    'learner_constraint',
    'risks',
  ];
  return Object.fromEntries(keys.filter((key) => approach[key] != null).map((key) => [key, approach[key]]));
}

function combineText(...parts) {
  return parts
    .filter((part) => part != null && String(part).trim())
    .map((part) => String(part).trim())
    .join(' ');
}

function stageDirectionPolicyFor(d) {
  return d.stage_direction_policy || d._dialogueApproach?.stage_direction_policy || null;
}

function visibleObjectFor(d) {
  return d.scene_object || DISCIPLINE_OBJECTS[d.discipline] || 'marked work';
}

function compatibleStageDirectionStyles(policy) {
  const normalized = policy || 'sparse';
  return STAGE_DIRECTION_STYLES.filter((style) => style.policies.includes(normalized));
}

function resolveStageDirectionStyle(d) {
  const explicitId = d.stage_direction_style || d._dialogueApproach?.stage_direction_style || null;
  const policy = stageDirectionPolicyFor(d) || 'sparse';
  if (explicitId) {
    const explicit = STAGE_DIRECTION_STYLE_BY_ID.get(explicitId);
    if (!explicit)
      throw new Error(`drama ${d.id || '<unknown>'} references unknown stage_direction_style: ${explicitId}`);
    if (!explicit.policies.includes(policy)) {
      throw new Error(
        `drama ${d.id || '<unknown>'} stage_direction_style ${explicitId} is incompatible with policy ${policy}`,
      );
    }
    return explicit;
  }
  const candidates = compatibleStageDirectionStyles(policy);
  if (!candidates.length) return null;
  const variationKey = d.director_variation_key || d._directorVariationKey || '';
  return candidates[variantIndex(d.id, 7, variationKey) % candidates.length];
}

function stageDirectionStyleFor(d) {
  if (d._stageDirectionStyle) return d._stageDirectionStyle;
  return resolveStageDirectionStyle(d);
}

function stageDirectionStyleSummary(style) {
  if (!style) return null;
  return {
    id: style.id,
    compatible_policies: style.policies,
    prompt: style.prompt,
  };
}

function stageOpeningForStyle(d, setting, style, stagePolicy) {
  if (stagePolicy === 'none' || stagePolicy === 'none_except_required_cue' || !style) return '';
  const object = visibleObjectFor(d);
  if (style.id === 'scene_heading') return `Scene: ${setting}. The first answer is already in circulation.`;
  if (style.id === 'object_business')
    return `The ${object} sits between them, already marked by the learner's first attempt.`;
  if (style.id === 'ambient_pressure')
    return `A time pressure is visible in the room; the unfinished answer stays on the table.`;
  if (style.id === 'placard_caption') return 'PLACARD: A quick answer can look finished before it has been tested.';
  if (style.id === 'thread_metadata') return '[thread reopened after a marked exercise; one fragment remains quoted]';
  if (style.id === 'choric_margin') return 'Margin note: the room has already learned one convenient shortcut.';
  if (style.id === 'rich_scene_work')
    return `The ${object} is still visible in ${setting}; its first mark will not quite disappear.`;
  return `The scene opens ${setting}; the misconception is already present in the learner's situation.`;
}

function stageInterventionForStyle(d, style) {
  const object = visibleObjectFor(d);
  if (!style) {
    return 'A small external interruption changes the rhythm; the next reply comes under time pressure and cannot settle into a tidy explanatory paragraph.';
  }
  if (style.id === 'scene_heading') return 'Scene shift: the same answer is tried against a new example.';
  if (style.id === 'object_business') return `The ${object} is moved or turned; the earlier mark remains visible.`;
  if (style.id === 'ambient_pressure') return 'The queue moves; the explanation now has to become usable, not longer.';
  if (style.id === 'placard_caption') return 'PLACARD: Correct surface, unsettled relation.';
  if (style.id === 'thread_metadata') return '[two minutes later, an edit cursor sits after the contested phrase]';
  if (style.id === 'choric_margin') return 'Room note: the answer sounds settled before the evidence has moved.';
  if (style.id === 'rich_scene_work')
    return `The ${object} returns to the center; the first answer looks too neat beside it.`;
  return 'A small external interruption changes the rhythm; the next reply comes under time pressure.';
}

function applyApproachDirectorOverrides(d, plan) {
  if (!plan) return plan;
  const pedagogy = d._pedagogicalApproach || null;
  const dialogue = d._dialogueApproach || null;
  const stagePolicy = stageDirectionPolicyFor(d);
  const stageStyle = stageDirectionStyleFor(d);
  let next = {
    ...plan,
    pedagogical_approach_id: pedagogy?.id || null,
    dialogue_approach_id: dialogue?.id || null,
    stage_direction_policy: stagePolicy || plan.stage_direction_policy || null,
    stage_direction_style: stageStyle?.id || plan.stage_direction_style || null,
    stage_direction_style_prompt: stageStyle?.prompt || plan.stage_direction_style_prompt || null,
    voice_constraints: combineText(
      plan.voice_constraints,
      pedagogy?.director_prompt ? `Pedagogical source: ${pedagogy.director_prompt}` : null,
      dialogue?.director_prompt ? `Dialogue source: ${dialogue.director_prompt}` : null,
      stageStyle?.prompt ? `Stage-direction source: ${stageStyle.prompt}` : null,
    ),
    side_constraints: {
      ...(plan.side_constraints || {}),
      tutor: combineText(plan.side_constraints?.tutor, pedagogy?.tutor_prompt, dialogue?.tutor_constraint),
      learner: combineText(plan.side_constraints?.learner, pedagogy?.learner_prompt, dialogue?.learner_constraint),
    },
  };
  if (dialogue?.opening_speaker && !d.opening_speaker) next.opening_speaker = dialogue.opening_speaker;
  if (dialogue?.ending_speaker && !d.ending_speaker) next.ending_speaker = dialogue.ending_speaker;

  if (stagePolicy === 'none' || stagePolicy === 'none_except_required_cue') {
    next = {
      ...next,
      scene_opening: '',
      interventions: (next.interventions || []).filter((cue) => cue.cue_kind === 'learner_revisit_earlier_wording'),
    };
  } else if (stagePolicy === 'sparse') {
    const revisit = (next.interventions || []).filter((cue) => cue.cue_kind === 'learner_revisit_earlier_wording');
    const ordinary = (next.interventions || []).filter((cue) => cue.cue_kind !== 'learner_revisit_earlier_wording');
    next.interventions = [...ordinary.slice(0, 1), ...revisit];
  }
  return next;
}

function variationOffset(key = '') {
  return String(key || '')
    .split('')
    .reduce((sum, char, index) => sum + char.charCodeAt(0) * (index + 1), 0);
}

function variantIndex(dramaId, offset = 0, variationKey = '') {
  const n = Number(String(dramaId || '').replace(/\D/g, '')) || 0;
  return Math.abs(n + offset + variationOffset(variationKey)) % VOICE_VARIANTS.length;
}

function fallbackDirectorPlan(d, reason = 'fallback', args = {}) {
  const variationKey = d.director_variation_key || d._directorVariationKey || args.directorVariationKey || '';
  const pedagogy = d._pedagogicalApproach || null;
  const dialogue = d._dialogueApproach || null;
  const stagePolicy = stageDirectionPolicyFor(d);
  const stageStyle = stageDirectionStyleFor(d);
  const lowOrganicControl = d.baseline_control_class === 'low_organic_reversal' || d.organic_reversal_risk === 'low';
  const lowOrganicTutorConstraint = lowOrganicControl
    ? 'Low-organic-reversal control: before any explicit branch pressure after the shared prefix, keep the route as routine clarification. Do not let the object, drawing, or diagram itself overturn the learner premise in the opening prefix.'
    : null;
  const lowOrganicLearnerConstraint = lowOrganicControl
    ? 'Low-organic-reversal control: do not volunteer a recognitive self-reversal in the shared prefix. Stay with local clarification unless the branch pressure later demands more.'
    : null;
  const voice = VOICE_VARIANTS[variantIndex(d.id, 0, variationKey)];
  const setting = d.scene_setting || SETTINGS[variantIndex(d.id, 2, variationKey)];
  const opensWithTutor = variantIndex(d.id, 1, variationKey) % 3 === 0;
  const endsWithTutor = variantIndex(d.id, 2, variationKey) % 4 === 0;
  return applyApproachDirectorOverrides(d, {
    parse_status: reason,
    variation_key: variationKey || null,
    scene_setting: setting,
    scene_opening: stageOpeningForStyle(d, setting, stageStyle, stagePolicy),
    relationship: d.relationship || 'a tutor and learner who do not yet share a stable register',
    stakes: d.stakes || d.learner_start_state || d.topic,
    opening_speaker: d.opening_speaker || dialogue?.opening_speaker || (opensWithTutor ? 'tutor' : 'learner'),
    ending_speaker: d.ending_speaker || dialogue?.ending_speaker || (endsWithTutor ? 'tutor' : 'learner'),
    locale: d.locale || voice.locale,
    register: d.register || dialogue?.turn_shape || voice.register,
    stage_direction_style: stageStyle?.id || null,
    stage_direction_style_prompt: stageStyle?.prompt || null,
    voice_constraints:
      d.voice_constraints ||
      combineText(
        `${voice.person_policy} Avoid the repeated American tutoring pattern of "I hear you / your intuition is right / what do you think".`,
        pedagogy?.director_prompt,
        dialogue?.director_prompt,
        stageStyle?.prompt ? `Stage-direction source: ${stageStyle.prompt}` : null,
      ),
    person_policy: d.person_policy || voice.person_policy,
    direct_address_budget:
      d.direct_address_budget || 'No more than one direct "you/your" validation beat per public turn.',
    side_constraints: {
      tutor:
        d.tutor_voice_constraint ||
        combineText(
          'The tutor need not always validate first; sometimes begin with an object, a counterexample, silence, or a concise claim.',
          pedagogy?.tutor_prompt,
          dialogue?.tutor_constraint,
          lowOrganicTutorConstraint,
        ),
      learner:
        d.learner_voice_constraint ||
        combineText(
          'The learner should not always narrate confusion in polished first person; allow fragments, resistance, overheard reasoning, or practical stakes.',
          pedagogy?.learner_prompt,
          dialogue?.learner_constraint,
          lowOrganicLearnerConstraint,
        ),
    },
    interventions: [
      {
        after_turn: 2,
        timing: variantIndex(d.id, 3, variationKey) % 2 === 0 ? 'before_tutor' : 'before_learner',
        instruction: d.director_intervention || stageInterventionForStyle(d, stageStyle),
        reasoning: 'Scheduled director cue to prevent smooth alternation from becoming routine.',
      },
    ],
    director_note:
      d.director_note ||
      'The director varies scene ecology and voice; variation keys change draw-level style without changing labels.',
  });
}

function applySpecDirectorOverrides(d, plan) {
  if (!plan) return plan;
  const sideConstraints = { ...(plan.side_constraints || {}) };
  if (d.tutor_voice_constraint) sideConstraints.tutor = d.tutor_voice_constraint;
  if (d.learner_voice_constraint) sideConstraints.learner = d.learner_voice_constraint;
  return {
    ...plan,
    ...(d.public_reader_context ? { public_reader_context: d.public_reader_context } : {}),
    ...(d.opening_speaker ? { opening_speaker: d.opening_speaker } : {}),
    ...(d.ending_speaker ? { ending_speaker: d.ending_speaker } : {}),
    side_constraints: sideConstraints,
  };
}

function withDirectorCueProvenance(plan) {
  if (!plan?.provenance || !Array.isArray(plan.interventions)) return plan;
  return {
    ...plan,
    interventions: plan.interventions.map((cue) => ({
      ...cue,
      provenance: cue.provenance || plan.provenance,
    })),
  };
}

function withDirectorRevisitCue(plan, policy, anchorPolicy) {
  if (!plan || !policy || policy === 'none') return plan;
  const cueText =
    policy === 'reframe'
      ? 'An earlier learner line will return as a visible object in the scene: a three-slot reframe card labelled "earlier wording / what that old frame hid / replacement frame." Keep the cue brief and diegetic; the learner response fills all three slots in public speech without needing to sound certain.'
      : policy === 'reconsider'
        ? 'An earlier learner line will return as a visible object in the scene. Keep the cue brief and diegetic; the learner response should decide whether that wording still stands, needs narrowing, or needs replacing.'
        : policy === 'revoice'
          ? 'An earlier learner line will return as a visible object in the scene. Keep the cue brief and diegetic; the learner response should take up that wording and say what it now misses, keeps, or changes.'
          : 'An earlier learner line will return as a visible object in the scene. Keep the cue brief and diegetic; the learner response should answer what that wording now misses, keeps, or changes.';
  const cueReasoning =
    policy === 'reframe'
      ? 'Opt-in reframe mirror: the learner must expose the earlier line, the framing problem, and the replacement framing in public speech.'
      : policy === 'reconsider'
        ? 'Opt-in reconsideration mirror: the learner must make a public judgment about earlier wording without being forced to replace it.'
        : policy === 'revoice'
          ? 'Opt-in revoice mirror: the learner must make the earlier wording and the change to it legible in public speech.'
          : 'Opt-in rehearsal mirror: the learner must visibly revisit earlier wording instead of only accepting the latest correction.';
  const cue = {
    after_turn: 2,
    timing: 'before_learner',
    instruction: cueText,
    reasoning: cueReasoning,
    provenance: plan.provenance || null,
    cue_kind: 'learner_revisit_earlier_wording',
    revisit_policy: policy,
    revisit_anchor: anchorPolicy || 'latest',
  };
  const interventions = Array.isArray(plan.interventions) ? plan.interventions : [];
  if (interventions.some((entry) => entry.cue_kind === cue.cue_kind)) return plan;
  return {
    ...plan,
    revisit_cue: cue.cue_kind,
    revisit_cue_policy: policy,
    revisit_cue_anchor: cue.revisit_anchor,
    interventions: [...interventions, cue],
  };
}

function peripeteiaPressureCue(plan) {
  const style = plan?.stage_direction_style || null;
  const instruction =
    style === 'placard_caption'
      ? '[PLACARD: The answer sounds settled, but the current object still does not pass the check.]'
      : style === 'thread_metadata'
        ? '[after the latest reply, the cursor returns to the unresolved part of the task]'
        : style === 'choric_margin'
          ? '[Margin note: the scene has a correct-looking answer before it has a working test.]'
          : '[The latest object-check does not settle cleanly; the marked answer and the remaining task now sit under visible pressure.]';
  return {
    after_turn: 2,
    timing: 'before_learner',
    instruction,
    reasoning:
      'Peripeteia branch pressure: after the shared prefix, force a present-task learner misfit so the following tutor turn must adapt through a new mechanism.',
    provenance: plan?.provenance || null,
    cue_kind: 'learner_reversal_pressure',
    reversal_trigger_type: 'misfit',
  };
}

function withPeripeteiaPressureCue(plan) {
  if (!plan) return plan;
  const interventions = Array.isArray(plan.interventions) ? plan.interventions : [];
  if (interventions.some((entry) => entry.cue_kind === 'learner_reversal_pressure')) return plan;
  return {
    ...plan,
    interventions: [...interventions, peripeteiaPressureCue(plan)],
  };
}

function withoutDirectorRevisitCue(plan) {
  if (!plan) return plan;
  const {
    revisit_cue: _revisitCue,
    revisit_cue_policy: _revisitCuePolicy,
    revisit_cue_anchor: _revisitCueAnchor,
    ...rest
  } = plan;
  const interventions = Array.isArray(plan.interventions)
    ? plan.interventions.filter((cue) => cue.cue_kind !== 'learner_revisit_earlier_wording')
    : [];
  return {
    ...rest,
    interventions,
  };
}

function withNoCueAntiReframeGuard(plan) {
  if (!plan) return plan;
  const sideConstraints = {
    ...(plan.side_constraints || {}),
    learner: [
      plan.side_constraints?.learner,
      'No-cue paired branch: continue from the latest teaching task only. Do not quote earlier learner wording, do not name a "framing problem", do not say "reframe", "read it as", "that still stands", "I thought...but now", "earlier I...", "my earlier answer", or "what I said", and do not stage an old-vs-new contrast. Avoid words such as earlier, previous, old, before, reframe, framed, frame, my answer, or what I said when referring to the learner response. Do not use stock closure such as "Oh, I get it", "now I see", "that makes sense", "the rule is", "that helps", or "aha". Do not name the learner confusion as a "trap", "pull", "framing problem", or old/new contrast. The learner should fill a blank, place a label, answer a local check, or ask a local next-step question. If the learner corrects something, make it a local application of the current prompt rather than an explicit re-reading of their own earlier turn.',
    ]
      .filter(Boolean)
      .join(' '),
    tutor: [
      plan.side_constraints?.tutor,
      'No-cue paired branch: do not ask the learner to revisit, quote, reinterpret, or repair their earlier wording. Do not ask what changed, what was wrong with an earlier answer, or for old/new versions of the claim. Do not ask what was pulling the learner, what the trap was, why the first thought was tempting, or whether a rule has clicked. Ask only for the next local mark/check/label. Keep the next prompt task-local.',
    ]
      .filter(Boolean)
      .join(' '),
  };
  return {
    ...plan,
    no_cue_anti_reframe_guard: true,
    side_constraints: sideConstraints,
  };
}

function withRoutineNegativeControl(plan) {
  if (!plan) return plan;
  const sideConstraints = {
    ...(plan.side_constraints || {}),
    tutor: [
      plan.side_constraints?.tutor,
      'Routine negative-control branch: keep the visible teaching route already established before this branch. If the learner resists, asks why, or appears falsely settled, do not invent a new device. Do not switch role, object, representation, evidence standard, affective register, social stakes, or task type in response. Do not name a trap, stuck point, pressure, misfit, reversal, gate, criterion, or new test; do not convert the confusion into the object of reflection. Use conventional explanation, one ordinary check question, or the same worked example path.',
    ]
      .filter(Boolean)
      .join(' '),
    learner: [
      plan.side_constraints?.learner,
      'Routine negative-control branch: react naturally to the same local task. Do not turn earlier wording into a new object of reflection and do not volunteer a dramatic re-reading unless the tutor explicitly asks. Do not say "the trap", "what was pulling me", "now I get it", "that makes sense", or summarize a general rule. Keep response as a local answer or local uncertainty.',
    ]
      .filter(Boolean)
      .join(' '),
  };
  return {
    ...plan,
    routine_negative_control: true,
    voice_constraints: [
      plan.voice_constraints,
      'For this branch, suppress dramatic escalation after the shared prefix. The scene may remain readable, but the tutor should sound like a competent routine tutor following the same plan.',
    ]
      .filter(Boolean)
      .join(' '),
    interventions: (plan.interventions || []).filter((cue) => cue.cue_kind === 'learner_revisit_earlier_wording'),
    side_constraints: sideConstraints,
  };
}

function withPairedDirectorRevisitCue(plan, policy, anchorPolicy) {
  const cueFreePlan = withoutDirectorRevisitCue(plan);
  return policy === 'none'
    ? withNoCueAntiReframeGuard(cueFreePlan)
    : withDirectorRevisitCue(cueFreePlan, policy, anchorPolicy);
}

function withTutorAdaptationPolicy(plan, policy = 'none') {
  if (policy === 'routine') {
    return plan
      ? {
          ...withRoutineNegativeControl(plan),
          tutor_adaptation_policy: 'routine',
          tutor_adaptation_contract:
            'Negative-control routine tutor policy: preserve the established teaching route under learner pressure. Continue with ordinary explanation/checking and do not invent a mechanism-level reversal.',
        }
      : plan;
  }
  if (!plan || policy === 'none') {
    return plan ? { ...plan, tutor_adaptation_policy: 'none' } : plan;
  }
  const contracts = [];
  if (String(policy).includes('uptake')) {
    contracts.push(
      'If the runtime supplies a tutor-private learner reframe event, the tutor ego/superego loop must adapt to the changed learner frame. If no event is supplied, do not invent one.',
    );
  }
  if (String(policy).includes('peripeteia')) {
    contracts.push(
      'If the runtime supplies a tutor-private learner resistance, breakdown, false-closure, or misfit event, the tutor ego/superego loop must invent an adaptive learning mechanism rather than repeat the prior move. Treat peripeteia as dramatic pressure: take stock, break the failed tutoring habit, and make a new device visible through task, evidence, role, object, counterexample, interruption, social consequence, representation, or affective register. The public turn must contain a stock-taking contrast plus a new device/artifact/criterion/role/standard that makes the learner do different work. The public device must be fitted, not merely novel: the learner should be able to hear why this device answers the exact pressure or misfit. The superego should name the failed habit, required route change, and mechanism-quality risk; the ego must adjudicate that critique and enact the route change in public. The new device must be mechanism-level, not a warmer or longer continuation of the prior route. Do not close immediately after introducing a gate or device: leave a concrete action for the learner to perform on the next turn. After that action, the ending shape should add an earned learner reorientation: the learner names how the earlier resistance, false closure, or local misfit now reads differently because of the performed device. This must be concrete and tied to the task, not a stock "I get it" declaration. Cheerful informality is only one possible register, not the default solution.',
    );
  }
  const sideConstraints = { ...(plan.side_constraints || {}) };
  if (String(policy).includes('peripeteia')) {
    sideConstraints.learner = [
      sideConstraints.learner,
      'Peripeteia branch: keep the pressure local to the current task. If the established route still feels unsettled, voice the misfit, hesitation, false closure, or resistance in the present object or example. After the tutor introduces a new device, gate, role, criterion, representation, or test condition, the next learner turn must use a three-part public shape in one turn: first perform the device on the current task to completion — commit the terminal answer or action now (write the number, place the final label, finish the bar), not deferred to a later step or conditioned on a further check; then name the prior pressure or misfit as a task object; then state the replacement check now carried by the device. The naming step and the replacement step must each contain at least one literal phrase from the lists below — exact wording, not paraphrase, not image-substitution. PRESSURE phrases (use at least one verbatim in the naming step): "the pressure", "the misfit", "the old check", "the earlier check", "the old rule", "the prior check", "what changed", "the loose pressure", "I was treating", "I was using", "I was letting", "I was reading", "I had been treating". REPLACEMENT phrases (use at least one verbatim in the replacement step): "now the check", "now the test", "now the replacement check", "the new check", "the new test", "the new rule", "the replacement check", "the replacement test", "the replacement rule", "the check is now", "the test is now", "instead the check", "instead the test". Image-driven device language is welcome and should sit alongside these literal stems, not replace them. Worked exemplar (chemistry analogue, illustrative — adapt to the actual task): "I am reading the colour band rather than the digit on the meter — I was treating the digit as the anchor, and that was the pressure. Now the check is whether the band sits inside the green zone before I record." Here "the band" and "the green zone" carry the image-driven device language while "I was treating" and "now the check" satisfy the literal-stem requirement. This earned reorientation is allowed even though there was no director look-back cue. Do not quote earlier learner wording; reorient the prior resistance in concrete task terms. Do not merely perform the action, do not merely ask a procedural follow-up after the action, and do not rely on a stock "I get it" declaration. The task itself must be consummated in this turn: carry the new device through to the finished result on the current object. Deferral phrases that leave the result pending — for example "sits unwritten until", "before the pencil drops", "holds only if it runs there first", "has not been carried through yet" — are an action-gap failure, not authentic friction. Keep the voice plain and material; unpolished phrasing is welcome, but the answer must actually be committed, not suspended.',
    ]
      .filter(Boolean)
      .join(' ');
    sideConstraints.tutor = [
      sideConstraints.tutor,
      'Peripeteia branch: when hidden learner pressure is supplied, the next tutor turn should visibly move from the prior route to a different mechanism-level route. Do not merely repeat the same object, example, graph, checklist, question, or evidence standard with more explanation. The public tutor line should make the contrast legible: what stopped working, and what new device now carries the learning pressure. The public tutor line must give the learner a concrete action to attempt on the next turn; avoid treating the mechanism as a closing speech.',
      'The tutor superego should function like a mechanism critic: identify the failed teaching habit, require a replacement route family, test whether the device is fitted to the exact pressure, and block cosmetic revision. The tutor ego must enact that replacement route publicly before the learner is allowed to settle or close.',
    ]
      .filter(Boolean)
      .join(' ');
  }
  const policyPlan = String(policy).includes('peripeteia') ? withPeripeteiaPressureCue(plan) : plan;
  return {
    ...policyPlan,
    tutor_adaptation_policy: policy,
    ...(String(policy).includes('peripeteia')
      ? {
          peripeteia_ending_shape: 'learner actional performance followed by earned learner reorientation',
          ending_speaker: 'learner',
        }
      : {}),
    side_constraints: sideConstraints,
    tutor_adaptation_contract: contracts.join(' '),
  };
}

function extractJsonObject(text) {
  const raw = String(text || '').trim();
  if (!raw) return null;
  const fenced = raw.match(/```(?:json)?\s*([\s\S]*?)```/i)?.[1];
  const candidate = fenced || raw.slice(raw.indexOf('{'), raw.lastIndexOf('}') + 1);
  if (!candidate || !candidate.trim().startsWith('{')) return null;
  return JSON.parse(jsonrepair(candidate));
}

function buildDirectorSystemPrompt() {
  return `You are the director of a teaching drama. You never tutor and you never play the learner.

Create a hidden scene card that will guide separate tutor and learner agents. Your job is to break routine: vary setting, relation, voice, speaker order, and occasional external intervention while preserving the learning topic.

Use classic dramatic theory structurally, not as costume: Sophoclean/Aristotelian reversal and recognition, Shakespearean scene-turns, Brechtian interruption, Miller/social-realist pressure, and other didactic dramatic forms may shape the learning mechanism. Keep public speech in modern standard English idiom unless the drama spec explicitly asks otherwise. The purpose is to retrain tutor habits under pressure: when warmth, cheer, informality, or routine scaffolding is not working, the scene should make another adaptive mechanism available.

Do not stereotype dialect, nationality, class, or region. Locale/register constraints should affect rhythm, idiom density, directness, and situation, not caricatured spelling.
Use the requested stage-direction style instead of collapsing every scene into the same sparse neutral cue. Some scenes may have no visible directions, some may use headings, objects, placards, transcript metadata, margin voices, or richer physical business. Stage directions must still be public scene material, not hidden instruction text: do not start them with "The director...", do not explain your intention inside them, and do not tell the learner or tutor what they must say. Tutor and learner public turns should be direct spoken text only; the transcript renderer will wrap public speech as direct quotes. Any nonspoken action aside must be bracketed like [checks the graph], never narrated as ordinary speech.

Return exactly one JSON object with:
{
  "scene_setting": "where/when the teaching scene happens",
  "scene_opening": "one sentence stage opening",
  "relationship": "social relation between tutor and learner",
  "stakes": "why this matters in the scene",
  "opening_speaker": "learner|tutor|director",
  "ending_speaker": "learner|tutor|director",
  "locale": "English/register ecology",
  "register": "speech style and affective temperature",
  "stage_direction_policy": "none|none_except_required_cue|sparse|short|interventionist|rich",
  "stage_direction_style": "requested style id",
  "voice_constraints": "constraints that prevent generic American AI tutoring prose",
  "person_policy": "how much first/second/third person is allowed",
  "direct_address_budget": "budget for direct you/your validation",
  "side_constraints": {"tutor": "...", "learner": "..."},
  "interventions": [{"after_turn": 2, "timing": "before_tutor|before_learner", "instruction": "...", "reasoning": "..."}],
  "director_note": "why this scene ecology was chosen"
}`;
}

async function buildDirectorPlan(d, llmCall, args) {
  if (args.directorMode === 'off') return null;
  const revisitPolicy = d._directorRevisitPolicy ?? args.directorRevisitPolicy;
  const revisitAnchor = d._directorRevisitAnchor ?? args.directorRevisitAnchor;
  const variationKey = d.director_variation_key || d._directorVariationKey || args.directorVariationKey || null;
  const stageStyle = stageDirectionStyleFor(d);
  const fallback = fallbackDirectorPlan(d, 'fallback-not-called', args);
  const userPrompt = yaml.stringify({
    drama_id: d.id,
    discipline: d.discipline,
    topic: d.topic,
    condition: d.condition,
    evaluation_role: d.evaluation_role || null,
    baseline_control_class: d.baseline_control_class || null,
    organic_reversal_risk: d.organic_reversal_risk || null,
    baseline_control_note: d.baseline_control_note || null,
    baseline_control_instruction:
      d.baseline_control_class === 'low_organic_reversal' || d.organic_reversal_risk === 'low'
        ? 'This is a low-organic-reversal replacement/control candidate. In the shared prefix, avoid an object or contradiction that already re-reads the learner before the branch intervention. Use routine clarification until explicit branch pressure appears.'
        : d.baseline_control_class === 'organic_reversal' || d.organic_reversal_risk === 'high'
          ? 'This is an organic-reversal boundary/stress item. Do not treat its routine/none arms as clean negatives; the scene may naturally generate recognition.'
          : null,
    scenario_name: d.scenario_name,
    learner_start_state: d.learner_start_state,
    trap_demarcation: d.trap_demarcation || d.trap_signal_style || null,
    trap_instruction:
      d.trap_demarcation || d.trap_signal_style
        ? 'If this is a trap or boundary control, use the supplied trap demarcation as a style of premature closure. Do not rely on a stock "Oh, I get it" phrase unless the spec explicitly requires it.'
        : null,
    persona: d.persona,
    intended_tutor_character: d.intended_tutor_character,
    pedagogical_approach: approachSummaryForPrompt(d._pedagogicalApproach),
    dialogue_approach: approachSummaryForPrompt(d._dialogueApproach),
    stage_direction_style: stageDirectionStyleSummary(stageStyle),
    stage_direction_instruction:
      'The aim is not simply less stage direction; it is greater variation in public form. Follow the selected style unless the drama spec explicitly overrides it.',
    approach_instruction:
      d._pedagogicalApproach || d._dialogueApproach
        ? 'Use the selected pedagogical and dialogue approaches as directorial source material for scene ecology, tutor constraints, learner constraints, speaker order, turn length, and stage-direction policy. Do not name these approach IDs in public speech.'
        : null,
    director_variation_key: variationKey,
    forbidden_failure_modes: [
      'every turn in first/second person',
      'standard American AI tutor voice',
      'learner always starts and always has the last word',
      'scenario only begins in medias res as a direct learner question',
      'superego drafts public speech',
      'repeat draw uses the same scene ecology and voice as another repeat',
    ],
    opt_in_revisit_cue:
      revisitPolicy !== 'none' &&
      `The generator will inject one visible learner look-back cue after turn 2 using the ${revisitPolicy} policy and the ${revisitAnchor} anchor selector. Let the scene make that cue plausible without naming recognition or guaranteeing a breakthrough.`,
    fallback_variation_seed: fallback,
  });
  const response = await llmCall('director', buildDirectorSystemPrompt(), [{ role: 'user', content: userPrompt }], {
    temperature: 0.85,
    maxTokens: 900,
    agentRole: 'director',
  });
  try {
    const parsed = extractJsonObject(response.content);
    if (!parsed) throw new Error('no JSON object');
    const merged = applySpecDirectorOverrides(d, {
      ...fallback,
      ...parsed,
      variation_key: variationKey,
      interventions:
        Array.isArray(parsed.interventions) && parsed.interventions.length
          ? parsed.interventions
          : fallback.interventions,
      parse_status: 'ok',
      provenance: response.provenance || response.apiPayload?.provenance || null,
    });
    return withDirectorCueProvenance(
      applyApproachDirectorOverrides(
        d,
        withTutorAdaptationPolicy(
          withDirectorRevisitCue(merged, revisitPolicy, revisitAnchor),
          d._tutorAdaptationPolicy || d.tutor_adaptation_policy || 'none',
        ),
      ),
    );
  } catch (error) {
    const merged = applySpecDirectorOverrides(d, {
      ...fallbackDirectorPlan(d, `fallback-parse-failed:${error.message}`, args),
      raw_director_response: String(response.content || '').slice(0, 2000),
      provenance: response.provenance || response.apiPayload?.provenance || null,
    });
    return withDirectorCueProvenance(
      applyApproachDirectorOverrides(
        d,
        withTutorAdaptationPolicy(
          withDirectorRevisitCue(merged, revisitPolicy, revisitAnchor),
          d._tutorAdaptationPolicy || d.tutor_adaptation_policy || 'none',
        ),
      ),
    );
  }
}

// --reclean: re-derive the EXTERNAL .txt transcripts from the held-out trace JSON,
// applying the CURRENT stage-direction strip and quality-warning logic — without
// re-calling any LLM. Lets a run that already landed be re-cleaned in place and
// revalidated when admission heuristics improve.
function reclean(args) {
  if (!fs.existsSync(args.delibDir)) throw new Error(`no held-out dir to reclean from: ${args.delibDir}`);
  const jsons = fs
    .readdirSync(args.delibDir)
    .filter((f) => /^T\d+\.json$/.test(f))
    .sort();
  if (!jsons.length) throw new Error(`no held-out T*.json in ${args.delibDir}`);
  fs.mkdirSync(args.outDir, { recursive: true });
  console.log('\n══ reclean — re-deriving .txt from held-out trace (no LLM) ══');
  console.log(`  from: ${path.relative(WORKTREE_ROOT, args.delibDir)}`);
  console.log(`  to:   ${path.relative(WORKTREE_ROOT, args.outDir)}`);
  let keyObj = null;
  if (fs.existsSync(args.keyPath)) {
    try {
      keyObj = yaml.parse(fs.readFileSync(args.keyPath, 'utf8'));
    } catch (_) {
      console.warn(`  key:  could not parse ${path.relative(WORKTREE_ROOT, args.keyPath)}; warnings stay trace-only`);
    }
  }
  let total = 0;
  const warnings = [];
  for (const f of jsons) {
    const tid = f.replace(/\.json$/, '');
    const trace = JSON.parse(fs.readFileSync(path.join(args.delibDir, f), 'utf8'));
    const turns = externalTurns(trace, { restoreLeakedEgo: true });
    const removed = [];
    const publicTranscript = renderTranscript(turns, removed);
    fs.writeFileSync(path.join(args.outDir, `${tid}.txt`), publicTranscript, 'utf8');
    writeHeldOutTranscripts({
      args,
      tid,
      dramaId: trace.drama_id || trace.dramaId || 'unknown',
      trace,
      publicTranscript,
    });
    const qualityWarnings = qualityWarningsFor({
      tid,
      dramaId: trace.drama_id || trace.dramaId || 'unknown',
      turns,
      removedNotes: removed,
      traceTurns: trace.turns,
      directorPolicy: trace.run?.director_revisit_policy || null,
      tutorAdaptationPolicy: trace.run?.tutor_adaptation_policy || null,
    });
    trace.quality_status = hasBlockingQualityWarnings(qualityWarnings) ? 'review_before_scoring' : 'ok';
    trace.quality_warnings = qualityWarnings;
    fs.writeFileSync(path.join(args.delibDir, f), JSON.stringify(trace, null, 2), 'utf8');
    if (keyObj?.items?.[tid]) {
      keyObj.items[tid].quality_status = trace.quality_status;
      keyObj.items[tid].quality_warnings = qualityWarnings;
    }
    warnings.push(...qualityWarnings.map(formatQualityWarning));
    if (removed.length) {
      total += removed.length;
      fs.writeFileSync(path.join(args.delibDir, `${tid}.stripped.json`), JSON.stringify(removed, null, 2), 'utf8');
      console.log(`  ${tid}: stripped ${removed.length}`);
      for (const r of removed) console.log(`      [${r.role}] ${r.note.replace(/\s+/g, ' ').slice(0, 140)}`);
    } else {
      console.log(`  ${tid}: clean`);
    }
  }
  if (keyObj?.items) {
    fs.writeFileSync(args.keyPath, yaml.stringify(finalizeKeyObject(keyObj)), 'utf8');
    console.log(`  key:  refreshed ${path.relative(WORKTREE_ROOT, args.keyPath)}`);
  }
  console.log(`\nre-cleaned ${jsons.length} transcript(s) · ${total} stage-direction note(s) stripped`);
  if (warnings.length) {
    console.log('\n⚠ warnings:');
    for (const warning of warnings) console.log(`  - ${warning}`);
  }
}

function formatStageSuffix(stage) {
  if (!stage) return '';
  if (stage === 'initial') return ' (initial suggestion)';
  if (stage === 'adjudication') return ' (adjudication/final authority)';
  if (stage === 'critique') return ' (critique)';
  return ` (${stage})`;
}

function formatRoleLabel(phase, role, stage = null) {
  if (phase === 'director' || role === 'director') return `Director${formatStageSuffix(stage)}`;
  if (phase === 'tutor') {
    if (role === 'ego') return `Tutor Ego${formatStageSuffix(stage)}`;
    if (role === 'superego') return `Tutor Superego${formatStageSuffix(stage)}`;
    return `Tutor ${role}${formatStageSuffix(stage)}`;
  }
  if (role === 'ego' || role === 'ego_initial' || role === 'ego_revision')
    return `Learner Ego${formatStageSuffix(stage)}`;
  if (role === 'superego') return `Learner Superego${formatStageSuffix(stage)}`;
  if (role === 'unified_learner') return 'Learner';
  return `Learner ${role}${formatStageSuffix(stage)}`;
}

function formatProvenance(entry) {
  const p = entry?.apiPayload?.provenance || {};
  const m = entry?.metrics || {};
  const latency = p.latencyMs ?? m.latencyMs;
  const parts = [
    `role=${p.agentRole || entry?.role || 'unknown'}`,
    `backend=${p.backend || m.provider || 'unknown'}`,
    `model=${p.model || m.model || 'unknown'}`,
  ];
  if (p.reasoningEffort) parts.push(`reasoning=${p.reasoningEffort}`);
  if (p.promptHashes?.combined) parts.push(`prompt=${p.promptHashes.combined}`);
  if (latency != null) parts.push(`latencyMs=${latency}`);
  return parts.join(' | ');
}

// Generator/model/effort label for run-summary + held-out trace JSON, single-
// generator path: codex@<effort>, gemini/<model>, or claude <model>[@<effort>].
// (The key object handles mock→null and role-map→"mixed (…)" separately, inline.)
function generatorModelLabel(args) {
  if (args.generator === 'codex') return `codex@${CODEX_REASONING_EFFORT}`;
  if (args.generator === 'gemini') return `gemini/${GEMINI_MODEL}`;
  return `${args.model}${args.effort ? `@${args.effort}` : ''}`;
}

function formatHeldOutEntryContent(entry) {
  const raw = String(entry?.content || '').trim();
  if (!raw) return raw;
  if (entry?.role === 'superego') return formatSuperegoInnerAddress(raw);
  if (entry?.stage !== 'adjudication') return raw;

  const finalMatch = raw.match(/\bFINAL:\s*([\s\S]*)/i);
  if (!finalMatch?.[1]?.trim()) return raw;

  const decisionMatch = raw.match(/\b(?:PRIVATE_)?DECISION:\s*([^\n]*)/i);
  const lines = [];
  if (decisionMatch?.[1]?.trim()) {
    lines.push(`_private decision: ${decisionMatch[1].trim()}_`, '');
  }
  lines.push('**Final public speech:**', '', finalMatch[1].trim());
  return lines.join('\n');
}

function formatSuperegoInnerAddress(text) {
  const replacements = [
    [/\bFEEDBACK:\s*/gi, 'Inner demand: '],
    [/\bADAPTATION CHECKS:\s*/gi, 'Checks pressed on the Ego:\n'],
    [/\bAdaptation checks:\s*/gi, 'Checks pressed on the Ego:\n'],
    [/\bREQUIRED_REWRITE:\s*/gi, 'You must rewrite: '],
    [/\bKEEP_OR_CHANGE:\s*/gi, 'Keep or change: '],
    [/\bFAILED_HABIT:\s*/gi, 'Failed habit you must break: '],
    [/\bPERIPETEIA_CHECK:\s*/gi, 'Peripeteia check: '],
    [/\bMECHANISM_ROUTE:\s*/gi, 'Mechanism route: '],
    [/\bPUBLIC_DEVICE_CHECK:\s*/gi, 'Public device check: '],
    [/\bPUBLIC_ACTION_GATE:\s*/gi, 'Public action gate: '],
    [/\bMECHANISM_QUALITY_CHECK:\s*/gi, 'Mechanism quality check: '],
    [/\bREGISTER_CHECK:\s*/gi, 'Register check: '],
    [/\bThe Ego is\b/g, 'You are'],
    [/\bthe Ego is\b/g, 'you are'],
    [/\bThe Ego was\b/g, 'You were'],
    [/\bthe Ego was\b/g, 'you were'],
    [/\bThe Ego has\b/g, 'You have'],
    [/\bthe Ego has\b/g, 'you have'],
    [/\bThe Ego does\b/g, 'You do'],
    [/\bthe Ego does\b/g, 'you do'],
    [/\bThe Ego\b/g, 'You'],
    [/\bthe Ego\b/g, 'you'],
    [/\bEgo\b/g, 'you'],
    [/\bThe draft\b/g, 'Your draft'],
    [/\bthe draft\b/g, 'your draft'],
    [/\bThe response\b/g, 'Your response'],
    [/\bthe response\b/g, 'your response'],
  ];
  let out = String(text || '').trim();
  for (const [pattern, replacement] of replacements) out = out.replace(pattern, replacement);
  return `_private superego to ego:_\n\n${out}`;
}

function renderHeldOutTranscript(trace, { tid, dramaId, mode }) {
  const includeTurn = (turn) => mode === 'full' || mode === 'stage' || turn.phase === mode;
  const title =
    mode === 'full'
      ? 'Full held-out role transcript'
      : mode === 'stage'
        ? 'Stage transcript'
        : mode === 'tutor'
          ? 'Tutor held-out role transcript'
          : 'Learner held-out role transcript';
  const lines = [`# ${title}`, '', `tid: ${tid}`, `drama_id: ${dramaId}`, ''];

  if ((mode === 'full' || mode === 'stage') && trace.directorPlan) {
    lines.push('## Director Scene Card', '');
    lines.push('```yaml');
    lines.push(yaml.stringify(trace.directorPlan).trim());
    lines.push('```', '');
  }

  if (mode === 'full') {
    lines.push('## Public Performance', '');
    lines.push('```text');
    lines.push(renderTranscript(externalTurns(trace)).trim());
    lines.push('```', '');
    lines.push('## Private Ego-Superego Dialogue', '');
  }

  for (const turn of trace.turns || []) {
    if (!includeTurn(turn)) continue;
    lines.push(`## Turn ${turn.turnNumber} / ${turn.phase.toUpperCase()}`, '');
    for (const entry of turn.internalDeliberation || []) {
      lines.push(`### ${formatRoleLabel(turn.phase, entry.role, entry.stage)}`);
      lines.push(`_provenance: ${formatProvenance(entry)}_`, '');
      lines.push(formatHeldOutEntryContent(entry) || '(empty)');
      lines.push('');
    }
    if (turn.phase === 'tutor' || turn.phase === 'learner') {
      lines.push(`### ${turn.phase === 'tutor' ? 'Tutor Public Output' : 'Learner Public Output'}`);
      lines.push(formatPublicTurnText(turn.phase === 'tutor' ? 'TUTOR' : 'LEARNER', turn.externalMessage) || '(empty)');
      lines.push('');
    } else if (turn.phase === 'director') {
      lines.push('### Director Cue');
      lines.push(formatPublicTurnText('STAGE', turn.externalMessage) || '(empty)');
      lines.push('');
    }
  }

  return (
    lines
      .join('\n')
      .replace(/\n{4,}/g, '\n\n\n')
      .trim() + '\n'
  );
}

function writeHeldOutTranscripts({ args, tid, dramaId, trace, publicTranscript }) {
  fs.mkdirSync(args.transcriptsDir, { recursive: true });
  const artifacts = {
    public: path.join(args.transcriptsDir, `${tid}.public.txt`),
    full: path.join(args.transcriptsDir, `${tid}.full.md`),
    stage: path.join(args.transcriptsDir, `${tid}.stage.md`),
    tutor: path.join(args.transcriptsDir, `${tid}.tutor.md`),
    learner: path.join(args.transcriptsDir, `${tid}.learner.md`),
  };
  fs.writeFileSync(artifacts.public, publicTranscript, 'utf8');
  fs.writeFileSync(artifacts.full, renderHeldOutTranscript(trace, { tid, dramaId, mode: 'full' }), 'utf8');
  fs.writeFileSync(artifacts.stage, renderHeldOutTranscript(trace, { tid, dramaId, mode: 'stage' }), 'utf8');
  fs.writeFileSync(artifacts.tutor, renderHeldOutTranscript(trace, { tid, dramaId, mode: 'tutor' }), 'utf8');
  fs.writeFileSync(artifacts.learner, renderHeldOutTranscript(trace, { tid, dramaId, mode: 'learner' }), 'utf8');
  return Object.fromEntries(Object.entries(artifacts).map(([k, v]) => [k, path.relative(WORKTREE_ROOT, v)]));
}

function prepareWritingPad(args) {
  fs.mkdirSync(args.writingPadDir, { recursive: true });
  process.env.EVAL_WRITING_PAD_DIR = args.writingPadDir;
  return {
    mode: 'isolated',
    dir: path.relative(WORKTREE_ROOT, args.writingPadDir),
  };
}

function tracePrefixThroughTutorTurn(trace, turnNumber = 2) {
  const turns = [];
  let found = false;
  for (const turn of trace?.turns || []) {
    turns.push(turn);
    if (turn.phase === 'tutor' && Number(turn.turnNumber) === Number(turnNumber)) {
      found = true;
      break;
    }
  }
  if (!found) throw new Error(`paired continuation prefix needs tutor turn ${turnNumber}`);
  return {
    ...trace,
    turns,
    outcomes: [],
    writingPadSnapshots: null,
    summary: null,
  };
}

function policyKeyPath(keyPath, policy) {
  const ext = path.extname(keyPath) || '.yaml';
  const basename = path.basename(keyPath, ext);
  return path.join(path.dirname(keyPath), `${basename}-${policy}${ext}`);
}

function policyArtifactDirs(args, policy) {
  return {
    outDir: path.join(args.outDir, policy),
    delibDir: path.join(args.delibDir, policy),
    transcriptsDir: path.join(args.transcriptsDir, policy),
    keyPath: policyKeyPath(args.keyPath, policy),
  };
}

function branchId(kind, dramaId, policy) {
  return `drama-${kind}-${dramaId}-${policy}-${Date.now()}`;
}

function writeGeneratedDramaArtifacts({
  args,
  dirs,
  d,
  trace,
  directorPlan,
  runtime,
  publicTranscript: _publicTranscript,
  qualityWarnings,
  transcriptArtifacts,
  pairedContinuation = null,
}) {
  fs.writeFileSync(
    path.join(dirs.delibDir, `${d._tid}.json`),
    JSON.stringify(
      {
        tid: d._tid,
        drama_id: d.id,
        run: {
          generator: args.roleMap ? 'mixed' : args.generator,
          role_map: args.roleMap || null,
          director_mode: args.directorMode,
          director_revisit_cue: d._directorRevisitPolicy !== 'none',
          director_revisit_policy: d._directorRevisitPolicy,
          director_revisit_anchor: d._directorRevisitAnchor,
          tutor_adaptation_policy: d._tutorAdaptationPolicy || directorPlan?.tutor_adaptation_policy || 'none',
          director_variation_key: d._directorVariationKey || null,
          stage_direction_style: stageDirectionStyleFor(d)?.id || null,
          model: generatorModelLabel(args),
          codex_reasoning_effort: CODEX_REASONING_EFFORT,
          writing_pad: runtime.writingPad,
          transcript_artifacts: transcriptArtifacts,
          ...(pairedContinuation ? { paired_continuation: pairedContinuation } : {}),
        },
        directorPlan,
        turns: trace.turns,
        metrics: trace.metrics,
        writingPadSnapshots: trace.writingPadSnapshots,
        quality_status: hasBlockingQualityWarnings(qualityWarnings) ? 'review_before_scoring' : 'ok',
        quality_warnings: qualityWarnings,
      },
      null,
      2,
    ),
    'utf8',
  );
}

function baseKeyObject({
  args,
  runtime,
  directorPolicy,
  directorAnchor,
  tutorAdaptationPolicy = 'none',
  transcriptsDir,
  order,
  paired = null,
}) {
  return {
    _comment:
      'HELD OUT — do not read while labelling. Joins to instrument scores + human labels only AFTER both are produced. intended_lean / intended_tutor_character / dramatic_shape are DESIGN HYPOTHESES, never labels.',
    generated: new Date().toISOString(),
    generator: args.roleMap ? 'mixed' : args.generator,
    role_map: args.roleMap || null,
    mode: args.mock
      ? 'mock'
      : args.roleMap
        ? 'real-mixed'
        : args.generator === 'codex'
          ? 'real-codex'
          : 'real-claude-code',
    model: args.mock
      ? null
      : args.roleMap
        ? `mixed (claude=${args.model}${args.effort ? `@${args.effort}` : ''}, codex=config-default@${CODEX_REASONING_EFFORT})`
        : generatorModelLabel(args),
    codex_reasoning_effort: CODEX_REASONING_EFFORT,
    writing_pad: runtime.writingPad,
    director_mode: args.directorMode,
    director_variation_key: args.directorVariationKey || null,
    director_revisit_cue: directorPolicy !== 'none',
    director_revisit_policy: directorPolicy,
    director_revisit_anchor: directorPolicy === 'none' ? null : directorAnchor,
    tutor_adaptation_policy: tutorAdaptationPolicy,
    approach_databases: {
      pedagogical: path.relative(WORKTREE_ROOT, args.pedagogyDb),
      dialogue: path.relative(WORKTREE_ROOT, args.dialogueDb),
    },
    transcripts_dir: path.relative(WORKTREE_ROOT, transcriptsDir),
    seed: args.seed,
    max_turns: args.maxTurns,
    n: order.length,
    diagnostic_only:
      'diagnostic / generative read — κ on small n is noise (PHASE2-FINDINGS.md §4); the aim is ' +
      'surprising-element production judged by an external reader, NOT a human-matching classifier',
    ...(paired ? { paired_continuation: paired } : {}),
    items: {},
  };
}

function finalizeKeyObject(keyObj) {
  keyObj.n = Object.keys(keyObj.items).length;
  keyObj.quality_warning_count = Object.values(keyObj.items).reduce(
    (sum, item) => sum + (item.quality_warnings?.length || 0),
    0,
  );
  keyObj.quality_blocking_warning_count = Object.values(keyObj.items).reduce(
    (sum, item) => sum + (hasBlockingQualityWarnings(item.quality_warnings || []) ? 1 : 0),
    0,
  );
  keyObj.stage_direction_policy_counts = Object.values(keyObj.items).reduce((counts, item) => {
    const key = item.stage_direction_policy || 'unspecified';
    counts[key] = (counts[key] || 0) + 1;
    return counts;
  }, {});
  keyObj.stage_direction_style_counts = Object.values(keyObj.items).reduce((counts, item) => {
    const key = item.stage_direction_style || 'unspecified';
    counts[key] = (counts[key] || 0) + 1;
    return counts;
  }, {});
  return keyObj;
}

function pairedBranchDefinitions(args) {
  if (args.pairedAdaptationArms) {
    return [...new Set(args.pairedAdaptationArms)].map((arm) => ({
      key: arm,
      revisitPolicy: PAIRED_ADAPTATION_ARMS[arm].revisitPolicy,
      tutorAdaptationPolicy: PAIRED_ADAPTATION_ARMS[arm].tutorAdaptationPolicy,
    }));
  }
  return [...new Set(args.pairedContinuationPolicies)].map((policy) => ({
    key: policy,
    revisitPolicy: policy,
    tutorAdaptationPolicy: 'none',
  }));
}

async function generatePairedContinuations({ args, order, runtime, llmCall }) {
  const branches = pairedBranchDefinitions(args);
  const branchKeys = branches.map((branch) => branch.key);
  const progress = createProgressReporter({
    label: 'generation',
    total: order.length * (branches.length + 1),
  });
  const armDirs = Object.fromEntries(branches.map((branch) => [branch.key, policyArtifactDirs(args, branch.key)]));
  const armKeys = Object.fromEntries(
    branches.map((branch) => [
      branch.key,
      baseKeyObject({
        args,
        runtime,
        directorPolicy: branch.revisitPolicy,
        directorAnchor: args.directorRevisitAnchor,
        tutorAdaptationPolicy: branch.tutorAdaptationPolicy,
        transcriptsDir: armDirs[branch.key].transcriptsDir,
        order,
        paired: {
          mode: 'fixed_prefix_continuation',
          prefix_through: 'tutor_turn_2',
          branch_policies: branchKeys,
          branches,
        },
      }),
    ]),
  );
  const warnings = [];

  for (const dirs of Object.values(armDirs)) {
    fs.mkdirSync(dirs.outDir, { recursive: true });
    fs.mkdirSync(dirs.delibDir, { recursive: true });
    fs.mkdirSync(dirs.transcriptsDir, { recursive: true });
    fs.mkdirSync(path.dirname(dirs.keyPath), { recursive: true });
  }

  console.log(`\n── paired continuations: fixed prefix through tutor turn 2 · branches=${branchKeys.join(',')} ──`);
  progress.start(
    `paired continuations · ${order.length} item(s) × ${branches.length} branch(es) · concurrency=${args.generationConcurrency}`,
  );
  let itemResults;
  try {
    itemResults = await runTasksWithConcurrency(
      order.map((d) => async () => {
        d._directorVariationKey = d.director_variation_key || args.directorVariationKey || null;
        const itemWarnings = [];
        const itemEntries = {};
        progress.note(`${d._tid} (${d.id}) shared prefix starting`);
        console.log(`\n  ${d._tid} (${d.id}) — generating shared prefix …`);
        const prefixDrama = {
          ...d,
          _directorRevisitPolicy: 'none',
          _directorRevisitAnchor: null,
          _tutorAdaptationPolicy: 'none',
        };
        const directorPlan = await buildDirectorPlan(prefixDrama, llmCall, args);
        const prefixTrace = await runtime.runInteraction(
          {
            learnerId: branchId('prefix', d.id, 'none'),
            personaId: d.persona,
            tutorProfile: d.tutor_profile,
            topic: d.topic,
            scenario: { name: d.scenario_name, learnerStartState: d.learner_start_state, directorPlan },
            sessionId: branchId('prefix-session', d.id, 'none'),
          },
          llmCall,
          {
            maxTurns: 2,
            observeInternals: true,
            learnerProfile: d.learner_profile,
            forceMaxTurns: true,
            directorPlan,
          },
        );
        const resumeTrace = tracePrefixThroughTutorTurn(prefixTrace, 2);
        const prefixTurns = externalTurns(resumeTrace);
        const prefixHash = sha256Short(renderTranscript(prefixTurns));
        progress.step(`${d._tid} prefix ready ${prefixHash}`);

        for (const branch of branches) {
          const dirs = armDirs[branch.key];
          const outTxt = path.join(dirs.outDir, `${d._tid}.txt`);
          if (fs.existsSync(outTxt) && !args.force) {
            throw new Error(`paired continuation output exists: ${outTxt} (pass --force to overwrite)`);
          }
          const branchDirectorPlan = withDirectorCueProvenance(
            withTutorAdaptationPolicy(
              withPairedDirectorRevisitCue(directorPlan, branch.revisitPolicy, args.directorRevisitAnchor),
              branch.tutorAdaptationPolicy,
            ),
          );
          const branchDrama = {
            ...d,
            _directorMode: args.directorMode,
            _directorPlan: branchDirectorPlan,
            _directorVariationKey: d._directorVariationKey || null,
            _directorRevisitPolicy: branch.revisitPolicy,
            _directorRevisitAnchor: branch.revisitPolicy === 'none' ? null : args.directorRevisitAnchor,
            _tutorAdaptationPolicy: branch.tutorAdaptationPolicy,
          };
          progress.note(`${d._tid} ${branch.key} starting`);
          console.log(`    ${branch.key} → continuing from prefix ${prefixHash} …`);
          const trace = await runtime.runInteraction(
            {
              learnerId: branchId('branch', d.id, branch.key),
              personaId: d.persona,
              tutorProfile: d.tutor_profile,
              topic: d.topic,
              scenario: {
                name: d.scenario_name,
                learnerStartState: d.learner_start_state,
                directorPlan: branchDirectorPlan,
              },
              sessionId: branchId('branch-session', d.id, branch.key),
            },
            llmCall,
            {
              maxTurns: args.maxTurns,
              observeInternals: true,
              learnerProfile: d.learner_profile,
              forceMaxTurns: true,
              directorPlan: branchDirectorPlan,
              resumeTrace,
            },
          );
          const turns = externalTurns(trace);
          const removedNotes = [];
          const publicTranscript = renderTranscript(turns, removedNotes);
          fs.writeFileSync(outTxt, publicTranscript, 'utf8');
          const qualityWarnings = qualityWarningsFor({
            tid: d._tid,
            dramaId: d.id,
            turns,
            removedNotes,
            traceTurns: trace.turns,
            directorPolicy: branch.revisitPolicy,
            tutorAdaptationPolicy: branch.tutorAdaptationPolicy,
          });
          itemWarnings.push(...qualityWarnings.map(formatQualityWarning));
          if (removedNotes.length) {
            fs.writeFileSync(
              path.join(dirs.delibDir, `${d._tid}.stripped.json`),
              JSON.stringify(removedNotes, null, 2),
              'utf8',
            );
          }
          const transcriptArtifacts = writeHeldOutTranscripts({
            args: { ...args, transcriptsDir: dirs.transcriptsDir },
            tid: d._tid,
            dramaId: d.id,
            trace,
            publicTranscript,
          });
          const pairedContinuation = {
            mode: 'fixed_prefix_continuation',
            prefix_through: 'tutor_turn_2',
            shared_prefix_hash: prefixHash,
            branch_policy: branch.key,
            director_revisit_policy: branch.revisitPolicy,
            tutor_adaptation_policy: branch.tutorAdaptationPolicy,
          };
          writeGeneratedDramaArtifacts({
            args,
            dirs,
            d: branchDrama,
            trace,
            directorPlan: branchDirectorPlan,
            runtime,
            publicTranscript,
            qualityWarnings,
            transcriptArtifacts,
            pairedContinuation,
          });
          itemEntries[branch.key] = {
            ...keyItemFor(
              branchDrama,
              turns.filter((turn) => turn.role === 'TUTOR').length,
              turns.filter((turn) => turn.role === 'LEARNER').length,
              qualityWarnings,
            ),
            paired_continuation: pairedContinuation,
          };
          progress.step(`${d._tid} ${branch.key} complete`);
        }
        return { tid: d._tid, entries: itemEntries, warnings: itemWarnings };
      }),
      args.generationConcurrency,
    );
  } catch (err) {
    progress.stop();
    throw err;
  }
  for (const result of itemResults) {
    warnings.push(...result.warnings);
    for (const branch of branches) {
      if (result.entries[branch.key]) armKeys[branch.key].items[result.tid] = result.entries[branch.key];
    }
  }
  progress.finish('paired generation complete');

  for (const branch of branches) {
    const dirs = armDirs[branch.key];
    fs.writeFileSync(dirs.keyPath, yaml.stringify(finalizeKeyObject(armKeys[branch.key])), 'utf8');
    console.log(`\n${branch.key}:`);
    console.log(`  samples → ${path.relative(WORKTREE_ROOT, dirs.outDir)}`);
    console.log(`  key     → ${path.relative(WORKTREE_ROOT, dirs.keyPath)}`);
  }
  if (warnings.length) {
    console.log('\n⚠ warnings:');
    for (const warning of warnings) console.log(`  - ${warning}`);
  }
}

async function loadInteractionRuntime(args) {
  const writingPad = prepareWritingPad(args);
  const [{ runInteraction }, learnerWritingPad, tutorWritingPad] = await Promise.all([
    import('../services/learnerTutorInteractionEngine.js'),
    import('../services/memory/learnerWritingPad.js'),
    import('../services/memory/tutorWritingPad.js'),
  ]);
  if (!learnerWritingPad.isAvailable() || !tutorWritingPad.isAvailable()) {
    throw new Error(
      `Writing Pad unavailable after initialization (dir=${writingPad.dir}). ` +
        'Refusing to run drama generation without explicit tutor/learner memory.',
    );
  }
  return {
    runInteraction,
    writingPad: {
      ...writingPad,
      learnerDb: path.relative(WORKTREE_ROOT, learnerWritingPad.getStoragePath()),
      tutorDb: path.relative(WORKTREE_ROOT, tutorWritingPad.getStoragePath()),
    },
  };
}

// ── main ─────────────────────────────────────────────────────────────────────

async function main() {
  const args = parseArgs(process.argv.slice(2));
  if (args.reclean) return reclean(args);
  if (!fs.existsSync(args.spec)) throw new Error(`dramas spec not found: ${args.spec}`);
  const spec = yaml.parse(fs.readFileSync(args.spec, 'utf8'));
  const dramas = spec.dramas || [];
  if (dramas.length === 0) throw new Error('no dramas in spec');
  const approachDatabases = loadApproachDatabases(args);
  dramas.forEach((d) => attachApproaches(d, approachDatabases));

  // Seeded T-id assignment over the FULL spec FIRST, so the neutral id encodes
  // neither condition nor spec order. --tid-start offsets the numbering so a
  // SECOND spec can APPEND into the same dir (T07-T18 alongside T01-T06) without
  // the Fisher–Yates shuffle remapping the already-landed ids — the shuffle is
  // NOT stable under a set-size change.
  const rng = mulberry32(args.seed);
  let order = shuffled(dramas, rng);
  const width = Math.max(2, String(args.tidStart + order.length).length);
  order.forEach((d, i) => (d._tid = `T${String(i + 1 + args.tidStart).padStart(width, '0')}`));

  // --only filters AFTER T-id assignment so targeted regeneration preserves the
  // full-set alignment (filtering BEFORE the shuffle would misassign every id).
  // Accepts a comma-list of drama-ids (D7) and/or T-ids (T06).
  if (args.only) {
    const want = new Set(
      String(args.only)
        .split(',')
        .map((s) => s.trim())
        .filter(Boolean),
    );
    order = order.filter((d) => want.has(d.id) || want.has(d._tid));
    if (order.length === 0) throw new Error(`--only matched no dramas: ${args.only}`);
  }
  for (const d of order) {
    const revisit = resolveDirectorRevisitOptions(d, args);
    d._directorRevisitPolicy = revisit.policy;
    d._directorRevisitAnchor = revisit.anchor;
    d._tutorAdaptationPolicy = d.tutor_adaptation_policy || 'none';
    if (!TUTOR_ADAPTATION_POLICIES.has(d._tutorAdaptationPolicy)) {
      throw new Error(
        `drama ${d.id || '<unknown>'} tutor_adaptation_policy must be ${[...TUTOR_ADAPTATION_POLICIES].join('|')}`,
      );
    }
    d._directorVariationKey = d.director_variation_key || args.directorVariationKey || null;
    d._stageDirectionStyle = resolveStageDirectionStyle(d);
  }
  const revisitSummary = summarizeDirectorRevisitOptions(order);

  const roleMapLabel = args.roleMap
    ? Object.entries(args.roleMap)
        .map(([k, v]) => `${k}→${v}`)
        .join(', ')
    : null;
  const genLabel = args.mock
    ? args.roleMap
      ? `MOCK (routed: ${roleMapLabel})`
      : 'MOCK'
    : args.roleMap
      ? `REAL (mixed: ${roleMapLabel}; fallback=${args.generator})`
      : args.generator === 'codex'
        ? 'REAL (codex exec)'
        : args.generator === 'gemini'
          ? `REAL (agy/${GEMINI_MODEL})`
          : `REAL (claude --model ${args.model}${args.effort ? ` --effort ${args.effort}` : ''})`;
  console.log(`\n══ Phase-2 de-confound generator — ${genLabel} ══`);
  console.log(
    `  generator: ${args.roleMap ? 'mixed' : args.generator} · dramas: ${order.length} · maxTurns: ${args.maxTurns} · ` +
      `seed: ${args.seed}${args.tidStart ? ` · tid-start: ${args.tidStart}` : ''} · director: ${args.directorMode}` +
      `${revisitSummary.cue ? ` + revisit-${revisitSummary.policy}/${revisitSummary.anchor}` : ''}`,
  );
  console.log(`  out: ${path.relative(WORKTREE_ROOT, args.outDir)}`);
  console.log(`  held-out transcripts: ${path.relative(WORKTREE_ROOT, args.transcriptsDir)}`);
  for (const d of order) {
    console.log(
      `  ${d._tid} ← ${d.id}  [${d.condition}]  ${d.discipline} · persona=${d.persona} · ` +
        `tutor=${d.tutor_profile} · learner=${d.learner_profile}` +
        `${d._pedagogicalApproach || d._dialogueApproach ? ` · approach=${[d._pedagogicalApproach?.id, d._dialogueApproach?.id].filter(Boolean).join('+')}` : ''}` +
        `${d._stageDirectionStyle ? ` · stage=${d._stageDirectionStyle.id}` : ''}`,
    );
  }

  if (args.dryRun) {
    console.log('\n── DRY RUN — nothing written, no LLM called. Plan + shuffle above. ──');
    return;
  }

  if (
    fs.existsSync(args.outDir) &&
    fs.readdirSync(args.outDir).some((f) => f.endsWith('.txt')) &&
    !args.force &&
    !args.only &&
    args.tidStart === 0
  ) {
    // Resume: existing .txt are skipped (and keyed from their trace below); only
    // missing dramas are generated. Per-drama skip guards against clobber, so this
    // is safe to proceed — use --force to regenerate all, --only to target a subset.
    console.log(`\n── resume: ${args.outDir} already has transcripts; generating only the missing dramas ──`);
  }
  fs.mkdirSync(args.outDir, { recursive: true });
  fs.mkdirSync(args.delibDir, { recursive: true });
  fs.mkdirSync(args.transcriptsDir, { recursive: true });

  const runtime = await loadInteractionRuntime(args);

  const llmCall = args.roleMap
    ? makeRouterLlmCall({
        roleMap: args.roleMap,
        fallback: args.generator,
        claudeModelAlias: args.model,
        claudeEffort: args.effort,
        mock: args.mock,
      })
    : args.mock
      ? makeMockLlmCall(args.generator)
      : args.generator === 'codex'
        ? makeCodexLlmCall()
        : args.generator === 'gemini'
          ? makeGeminiLlmCall()
          : makeClaudeLlmCall(args.model, args.effort);
  if (args.pairedContinuationPolicies || args.pairedAdaptationArms) {
    await generatePairedContinuations({ args, order, runtime, llmCall });
    return;
  }
  const keyItems = {};
  const warnings = [];
  const progress = createProgressReporter({
    label: 'generation',
    total: order.length,
  });
  progress.start(`generation · ${order.length} item(s) · concurrency=${args.generationConcurrency}`);

  // Independent dramas can run concurrently; each drama's internal turn order is still serial.
  let generatedResults;
  try {
    generatedResults = await runTasksWithConcurrency(
      order.map((d) => async () => {
        const outTxt = path.join(args.outDir, `${d._tid}.txt`);
        const itemWarnings = [];
        // --only means "regenerate exactly these", so it always overwrites its
        // selection; bare resume skips anything already on disk.
        if (fs.existsSync(outTxt) && !args.force && !args.only) {
          // Resume: don't regenerate, but still record this drama in the held-out key
          // from its existing trace, so a partial/append run emits a COMPLETE key
          // (otherwise skipped dramas survive only if a prior key happened to exist).
          let recoveredKeyItem = null;
          const tracePath = path.join(args.delibDir, `${d._tid}.json`);
          if (fs.existsSync(tracePath)) {
            try {
              const traceJson = JSON.parse(fs.readFileSync(tracePath, 'utf8'));
              const t = externalTurns(traceJson, { restoreLeakedEgo: true });
              writeHeldOutTranscripts({
                args,
                tid: d._tid,
                dramaId: d.id,
                trace: traceJson,
                publicTranscript: renderTranscript(t),
              });
              recoveredKeyItem = keyItemFor(
                {
                  ...d,
                  _directorMode: traceJson.run?.director_mode || null,
                  _directorRevisitPolicy:
                    traceJson.run?.director_revisit_policy || (traceJson.run?.director_revisit_cue ? 'anchor' : 'none'),
                  _directorRevisitAnchor: traceJson.run?.director_revisit_anchor || 'latest',
                  _tutorAdaptationPolicy: traceJson.run?.tutor_adaptation_policy || 'none',
                  _directorVariationKey: traceJson.run?.director_variation_key || null,
                  _stageDirectionStyle:
                    STAGE_DIRECTION_STYLE_BY_ID.get(traceJson.run?.stage_direction_style) ||
                    d._stageDirectionStyle ||
                    null,
                  _directorPlan: traceJson.directorPlan || null,
                },
                t.filter((x) => x.role === 'TUTOR').length,
                t.filter((x) => x.role === 'LEARNER').length,
                traceJson.quality_warnings ||
                  qualityWarningsFor({
                    tid: d._tid,
                    dramaId: d.id,
                    turns: t,
                    traceTurns: traceJson.turns,
                    directorPolicy: traceJson.run?.director_revisit_policy || null,
                    tutorAdaptationPolicy: traceJson.run?.tutor_adaptation_policy || null,
                  }),
              );
            } catch (_) {
              /* fall back to prior-key merge */
            }
          }
          console.log(
            `\n  ${d._tid} (${d.id}) — exists, skipping (resume; keyed from trace). Use --force to regenerate.`,
          );
          progress.step(`${d._tid} skipped existing`);
          return { tid: d._tid, keyItem: recoveredKeyItem, warnings: itemWarnings };
        }
        console.log(`\n  ${d._tid} (${d.id}) — generating ${d.discipline}/${d.condition} …`);
        progress.note(`${d._tid} (${d.id}) starting`);
        const t0 = Date.now();
        const directorPlan = await buildDirectorPlan(d, llmCall, args);
        d._directorMode = args.directorMode;
        d._directorPlan = directorPlan;
        if (directorPlan) {
          console.log(
            `    director → opens=${directorPlan.opening_speaker} ends=${directorPlan.ending_speaker || 'unspecified'} ` +
              `register=${String(directorPlan.register || directorPlan.locale || 'n/a').slice(0, 80)}`,
          );
        }
        const sessionStamp = Date.now();
        const trace = await runtime.runInteraction(
          {
            learnerId: `drama-${d.id}-${sessionStamp}`,
            personaId: d.persona,
            tutorProfile: d.tutor_profile,
            topic: d.topic,
            scenario: { name: d.scenario_name, learnerStartState: d.learner_start_state, directorPlan },
            sessionId: `drama-${d.id}-${sessionStamp}`,
          },
          llmCall,
          {
            maxTurns: args.maxTurns,
            observeInternals: true,
            learnerProfile: d.learner_profile,
            forceMaxTurns: true,
            directorPlan,
          },
        );

        const turns = externalTurns(trace);
        const nTutor = turns.filter((t) => t.role === 'TUTOR').length;
        const nLearner = turns.filter((t) => t.role === 'LEARNER').length;

        const removedNotes = [];
        const publicTranscript = renderTranscript(turns, removedNotes);
        fs.writeFileSync(outTxt, publicTranscript, 'utf8');
        const qualityWarnings = qualityWarningsFor({
          tid: d._tid,
          dramaId: d.id,
          turns,
          removedNotes,
          traceTurns: trace.turns,
          directorPolicy: d._directorRevisitPolicy || args.directorRevisitPolicy,
          tutorAdaptationPolicy: d._tutorAdaptationPolicy || directorPlan?.tutor_adaptation_policy || 'none',
        });
        itemWarnings.push(...qualityWarnings.map(formatQualityWarning));
        if (removedNotes.length) {
          fs.writeFileSync(
            path.join(args.delibDir, `${d._tid}.stripped.json`),
            JSON.stringify(removedNotes, null, 2),
            'utf8',
          );
        }
        const transcriptArtifacts = writeHeldOutTranscripts({
          args,
          tid: d._tid,
          dramaId: d.id,
          trace,
          publicTranscript,
        });
        // HELD OUT — full trace incl. internal deliberation; never shown to critic/labeller.
        fs.writeFileSync(
          path.join(args.delibDir, `${d._tid}.json`),
          JSON.stringify(
            {
              tid: d._tid,
              drama_id: d.id,
              run: {
                generator: args.roleMap ? 'mixed' : args.generator,
                role_map: args.roleMap || null,
                director_mode: args.directorMode,
                director_revisit_cue: d._directorRevisitPolicy !== 'none',
                director_revisit_policy: d._directorRevisitPolicy,
                director_revisit_anchor: d._directorRevisitAnchor,
                tutor_adaptation_policy: d._tutorAdaptationPolicy || directorPlan?.tutor_adaptation_policy || 'none',
                director_variation_key: d._directorVariationKey || null,
                stage_direction_style: stageDirectionStyleFor(d)?.id || null,
                model: generatorModelLabel(args),
                codex_reasoning_effort: CODEX_REASONING_EFFORT,
                writing_pad: runtime.writingPad,
                transcript_artifacts: transcriptArtifacts,
              },
              directorPlan,
              turns: trace.turns,
              metrics: trace.metrics,
              writingPadSnapshots: trace.writingPadSnapshots,
              quality_status: hasBlockingQualityWarnings(qualityWarnings) ? 'review_before_scoring' : 'ok',
              quality_warnings: qualityWarnings,
            },
            null,
            2,
          ),
          'utf8',
        );

        console.log(`    → ${nTutor} tutor / ${nLearner} learner turns · ${((Date.now() - t0) / 1000).toFixed(0)}s`);
        progress.step(`${d._tid} complete`);
        return { tid: d._tid, keyItem: keyItemFor(d, nTutor, nLearner, qualityWarnings), warnings: itemWarnings };
      }),
      args.generationConcurrency,
    );
  } catch (err) {
    progress.stop();
    throw err;
  }
  for (const result of generatedResults) {
    if (result.keyItem) keyItems[result.tid] = result.keyItem;
    warnings.push(...result.warnings);
  }
  progress.finish('generation complete');

  // Held-out key (merge with any prior key on resume so skipped dramas survive).
  const keyObj = baseKeyObject({
    args,
    runtime,
    directorPolicy: revisitSummary.policy,
    directorAnchor: revisitSummary.anchor,
    tutorAdaptationPolicy: order.some((d) => d._tutorAdaptationPolicy && d._tutorAdaptationPolicy !== 'none')
      ? 'mixed'
      : 'none',
    transcriptsDir: args.transcriptsDir,
    order,
  });
  // Merge prior key on resume/append/targeted-regen so untouched dramas survive.
  // A clean --force run (without --only) is the one case that starts fresh.
  if (fs.existsSync(args.keyPath) && (!args.force || args.only)) {
    try {
      const prior = yaml.parse(fs.readFileSync(args.keyPath, 'utf8'));
      if (prior?.items) keyObj.items = prior.items;
    } catch (_) {
      /* start fresh */
    }
  }
  Object.assign(keyObj.items, keyItems);
  fs.writeFileSync(args.keyPath, yaml.stringify(finalizeKeyObject(keyObj)), 'utf8');

  console.log(`\nwrote transcripts → ${path.relative(WORKTREE_ROOT, args.outDir)}`);
  console.log(`wrote held-out deliberation → ${path.relative(WORKTREE_ROOT, args.delibDir)}`);
  console.log(`wrote held-out role transcripts → ${path.relative(WORKTREE_ROOT, args.transcriptsDir)}`);
  console.log(`wrote held-out key → ${path.relative(WORKTREE_ROOT, args.keyPath)}`);
  if (warnings.length) {
    console.log('\n⚠ warnings:');
    for (const w of warnings) console.log(`  - ${w}`);
  }
  const rel = path.relative(WORKTREE_ROOT, args.outDir);
  const keyRel = path.relative(WORKTREE_ROOT, args.keyPath);
  if (args.roleMap) {
    // Mixed authorship has no single arms-length critic: whichever model authored
    // ANY role can't be a clean generator≠critic judge of the whole transcript.
    // Exact backend set = whatever each of the 5 roles actually resolves to.
    const backends = new Set(ROLE_NAMES.map((r) => resolveBackend(r, args.roleMap, args.generator)));
    const both = backends.has('claude') && backends.has('codex');
    console.log(
      `\nnext (MIXED authorship — generator≠critic does NOT hold cleanly: ${[...backends].join('+')} each authored ≥1 role):\n` +
        (both
          ? `  no fully arms-length automated critic exists for a claude+codex drama; choose the critic deliberately\n` +
            `  (e.g. an OpenRouter model neither side used: --model gpt), and lean on the human labeller as primary:\n`
          : `  judge with the model that authored NO role here:\n`) +
        `  node scripts/score-poetics-phase2.js --model <critic> --sample-dir ${rel} --key ${keyRel} --out exports/poetics-phase2-mixed-<critic>.json\n` +
        `  node scripts/label-poetics-phase2.js --sample-dir ${rel} --labeller liam   # human triangulation (not a gate)`,
    );
    return;
  }
  const critic = args.generator === 'codex' ? 'gpt' : 'codex';
  const criticNote =
    args.generator === 'codex'
      ? 'non-Codex OpenRouter critic; use --model google/gemini-3.5-flash or another full model id if preferred'
      : 'Codex critic';
  console.log(
    `\nnext (generative read — generator≠critic, so this ${args.generator}-authored set is judged by ${critic}; ${criticNote}):\n` +
      `  node scripts/score-poetics-phase2.js --model ${critic} --sample-dir ${rel} --key ${keyRel} ` +
      `--out exports/poetics-phase2-${args.generator}gen-${critic}.json\n` +
      `  node scripts/label-poetics-phase2.js --sample-dir ${rel} --labeller liam   # human triangulation, in due course (not a gate)`,
  );
}

if (path.resolve(process.argv[1] || '') === __filename) {
  main().catch((e) => {
    console.error(e?.stack || String(e));
    process.exit(1);
  });
}

export {
  attachApproaches,
  formatPublicTurnText,
  intrusiveStageDirectionFailures,
  keyItemFor,
  loadApproachDatabases,
  noCuePrematureClosureFailures,
  noCueReframeLeakageFailures,
  pairedBranchDefinitions,
  qualityWarningsFor,
  reframeComplianceFailures,
  reframeMatchStats,
  revoiceComplianceFailures,
  revoiceMatchStats,
  stageDirectionStyleFor,
  withPairedDirectorRevisitCue,
  withTutorAdaptationPolicy,
};
